		computed: {
			...mapState({
				checkoutInfo: state => state.shopping.checkoutInfo,
				checkout_done: state => state.shopping.checkout_done
			}),
			// 是否需要上传营业执照信息（0是不需要传了，上传过）
			is_need_up_user_type_data() {
				return this.checkoutInfo && this.checkoutInfo.is_need_up_user_type_data !== undefined 
					? this.checkoutInfo.is_need_up_user_type_data 
					: 0;
			},
			isConditionMet() {
				  return (
					this.checkoutInfo.use_membership_card > 0 &&
					this.vipCard.membership_card_discount_price > 0
				  );
				},
			// 匹配 商品名称和商品规格
			processedGoodsList() {
				// 安全检查：确保数据存在且是数组
				if (!this.checkoutInfo || typeof this.checkoutInfo !== 'object' || !this.checkoutInfo.goods_list || !Array.isArray(this.checkoutInfo.goods_list) || this.checkoutInfo.goods_list.length === 0) {
					return [];
				}
				
				return this.checkoutInfo.goods_list.map(shop => {
						const {
							goods,
							goods_new
						} = shop;
						// 创建一个映射，以 goods_id 为键，值为对应的所有相关的 goods_new 项
						const goodsNewMap = new Map();
					
						goods_new.forEach((subArray, groupIndex) => {
							subArray.forEach(newItem => {
								if (!goodsNewMap.has(newItem.goods_id)) {
									goodsNewMap.set(newItem.goods_id, []);
								}
								goodsNewMap.get(newItem.goods_id).push({
									...newItem,
									group: groupIndex // 记录该项属于哪个子数组组
								});
							});
						});
					
						// 处理每个商品
						const updatedGoods = goods.map(good => {
							const goodsId = good.goods_id;
							const newItemsData = goodsNewMap.get(goodsId) || [];
					
							if (newItemsData.length > 0) {
								// 分类处理 goods_new 项为 goods_attrs 和 gifts
								const classifiedItems = {
									goods_attrs: [],
									gifts: []
								};
					
								newItemsData.forEach(newItem => {
									if (newItem.goods_attr && newItem.goods_attr.trim() !== "") {
										classifiedItems.goods_attrs.push({
											goods_attr: newItem.goods_attr.trim(),
											goods_price_format: newItem.goods_price_format,
											goods_number: newItem.goods_number,
											group: newItem.group // 保留组信息
										});
									} else {
										classifiedItems.gifts.push({
											goods_price_format: newItem.goods_price_format,
											goods_number: newItem.goods_number,
											group: newItem.group // 保留组信息
										});
									}
								});
					
								// 按组组织 goods_attrs 和 gifts
								const groupedByGroup = {};
					
								classifiedItems.goods_attrs.forEach(attr => {
									if (!groupedByGroup[attr.group]) {
										groupedByGroup[attr.group] = {
											goods_attrs: [],
											gifts: []
										};
									}
									groupedByGroup[attr.group].goods_attrs.push(attr);
								});
					
								classifiedItems.gifts.forEach(gift => {
									if (!groupedByGroup[gift.group]) {
										groupedByGroup[gift.group] = {
											goods_attrs: [],
											gifts: []
										};
									}
									groupedByGroup[gift.group].gifts.push(gift);
								});
					
								// 获取所有组别
								const groupKeys = Object.keys(groupedByGroup);
					
								// 将 groupedByGroup 转换为数组形式，便于模板展示
								const newItems = groupKeys.map(groupKey => ({
									group: `分组 ${parseInt(groupKey) + 1}`, // 组别名称
									goods_attrs: groupedByGroup[groupKey].goods_attrs,
									gifts: groupedByGroup[groupKey].gifts
								}));
					
								return {
									...good,
									newItems: newItems.length > 0 ? newItems : {
										goods_attrs: [],
										gifts: []
									}
								};
							} else {
								// 没有对应的 goods_new 项，标记为赠品
								return {
									...good,
									newItems: {
										goods_attrs: [],
										gifts: [{
											goods_price_format: "0.00",
											goods_number: 1,
											group: "无" // 可选
										}]
									}
								};
							}
						});
					
						return {
							...shop,
							goods: updatedGoods
						};
					});
			},
			// 过滤 服务
			consignee_address() {
				if (this.checkoutInfo.consignee) {
					return this.checkoutInfo.consignee.province_name + this.checkoutInfo.consignee.city_name + this
						.checkoutInfo.consignee.district_name + this.checkoutInfo.consignee.street_name + this.checkoutInfo
						.consignee.address
				} else {
					return ''
				}
			},
			address_id() {
				if (this.checkoutInfo.consignee) {
					return this.checkoutInfo.consignee.address_id ? this.checkoutInfo.consignee.address_id : ''
				} else {
					return ''
				}
			},
			cart_id() {
				let rec_ids = []
				if (this.checkoutInfo.goods_list) {
					this.checkoutInfo.goods_list.forEach((v) => {
						v.goods.forEach((res) => {
							rec_ids.push(res.rec_id)
						})
					})
				}
				return rec_ids
			},
			bonusList() {
				return this.checkoutInfo.bonus_list ? this.checkoutInfo.bonus_list : 0
			},
			couponsList() {
				return this.checkoutInfo.coupons_list ? this.checkoutInfo.coupons_list : 0
			},
			valueCard() {
				return this.checkoutInfo.value_card ? this.checkoutInfo.value_card : 0
			},
			// 获取已选储值卡的余额总值（用于显示）
			selectedValueCardBalance() {
				// 【关键修复】当弹窗打开时，使用临时状态 tempValueCardId；关闭时，使用实际状态 valueCardObject.valueCardId
				const activeCardId = this.valueCardObject.valueCardBase ? this.tempValueCardId : this.valueCardObject.valueCardId;
				
				if (!activeCardId || activeCardId <= 0) {
					return '';
				}
				if (!this.checkoutInfo || !this.checkoutInfo.value_card || !Array.isArray(this.checkoutInfo.value_card)) {
					return '';
				}
				// 查找已选中的储值卡
				const selectedCard = this.checkoutInfo.value_card.find(card => Number(card.vid) === Number(activeCardId));
				if (selectedCard) {
					// 返回格式化后的余额（使用 card_money 余额，而不是 vc_value 面额）
					const balance = Number(selectedCard.card_money || 0) || 0;
					return balance > 0 ? this.currency + this.formatCurrencyValue(balance) : '';
				}
				return '';
			},
			payment_method() {
				return this.checkoutInfo.payment_list ? this.checkoutInfo.payment_list : ''
			},
			total: {
				get() {
					return this.checkoutInfo && this.checkoutInfo.total ? this.checkoutInfo.total : ''
				},
				set(val) {}
			},
			
			amountPrice : {
				get() {
					// 积分兑换场景仍沿用后端返回的积分值
					if (this.total && this.rec_type == 4) {
						this.price = this.total.exchange_integral;
						this.currency = '';
						return this.price;
					}

					// 优先使用 checkoutInfo.total.amount，其次 this.total.amount
					const totalObj = this.checkoutInfo && this.checkoutInfo.total
						? this.checkoutInfo.total
						: (this.total || null);
					const rawAmount = totalObj && totalObj.amount !== undefined
						? Number(totalObj.amount || 0)
						: 0;

					// 统一做一次精度处理
					if (this.moneyPrecision) {
						return this.moneyPrecision(rawAmount);
					}
					return Number(rawAmount.toFixed ? rawAmount.toFixed(2) : rawAmount);
				},
				set(val) {
					const num = Number(val || 0);
					if (this.checkoutInfo && this.checkoutInfo.total) {
						this.$set(this.checkoutInfo.total, 'amount', num);
					} else if (this.total) {
						this.$set(this.total, 'amount', num);
					}
				}
			},
			
			payableAmount() {
				return this.moneyPrecision(parseFloat(this.amountPrice) || 0);
			},
			amountPriceFormated() {
				const value = this.payableAmount;
				return value > 0 ? value.toFixed(2) : '0.00';
			},
			shipping() {
				let arr = []
				if (this.checkoutInfo.goods_list) {
					this.checkoutInfo.goods_list.forEach((v) => {
						arr.push(v.shipping.default_shipping)
					})
				}
				return arr
			},
			shippingFee() {
				let shippingFeePrice = 0

				if (this.shipping_fee && this.store_id == 0) {
					this.shipping_fee.forEach(v => {
						shippingFeePrice += Number(v)
					})
				}
				return shippingFeePrice.toFixed(2)
			},
			rateFee() {
				let ratePrice = 0
				if (this.rate_price && this.store_id == 0) {
					this.rate_price.forEach(v => {
						ratePrice += Number(v)
					})
				}
				return Number(parseFloat(ratePrice).toFixed(2));
			},
			surplusSelf: {
				get() {
					// 【修复】确保与 balancePaymentActive 同步
					// 如果 balancePaymentActive 为 true，但 use_surplus_val 为 0，同步更新
					if (this.balancePaymentActive && this.use_surplus_val === 0) {
						this.$nextTick(() => {
							this.use_surplus_val = 1;
						});
					}
					// 如果 balancePaymentActive 为 false，但 use_surplus_val 不为 0，同步更新
					if (!this.balancePaymentActive && this.use_surplus_val !== 0) {
						this.$nextTick(() => {
							this.use_surplus_val = 0;
						});
					}
					return this.balancePaymentActive && this.use_surplus_val !== 0
				},
				set(val) {
					this.use_surplus_val = val == true ? 1 : 0
					// 【修复】同步 balancePaymentActive
					if (val && !this.balancePaymentActive) {
						this.balancePaymentActive = true;
					} else if (!val && this.balancePaymentActive) {
						this.balancePaymentActive = false;
					}
				}
			},
			creditSelf: {
				get() {
					// 【修复】计算属性的 getter 应该是纯函数，不能有副作用
					// 直接返回 use_credit_val 的状态，不进行任何状态修改
					return this.use_credit_val === 1
				},
				set(val) {
					this.use_credit_val = val === true ? 1 : 0
				}
			},
			integralSelf() {
				return this.use_integral_val == 0 ? false : true
			},
			integralList() {
				if (this.checkoutInfo && Array.isArray(this.checkoutInfo.integral)) {
					return this.checkoutInfo.integral;
				}
				return [];
			},
			integralInfo() {
				const list = this.integralList;
				if (list.length > 0 && list[0]) {
					return list[0];
				}
				return {
					integral: 0,
					integral_money_formated: ''
				};
			},
			integral() {
				const info = this.integralInfo;
				return info.integral;
			},
			wechatPayDisplayText() {
				const payable = this.payableAmount;
				if (payable <= 0) {
					return '未使用';
				}
				return `${this.currency}${payable.toFixed(2)}`;
			},
			storeInfo() {
				return this.checkoutInfo.store
			},
			listShow() {
				return this.$store.state.shopping.listShow
			},
			invoiceValue() {
				//电子发票只显示明细 invoice.invoiceType == 2
				return this.invoice.invoiceType == 2 ? ['商品明细'] : this.checkoutInfo.invoice_content
			},
			valuecardBg() {
				return this.websiteUrl + '/img/ka_bg.jpg'
			},
			use_paypwd() {
				return this.checkoutInfo.use_paypwd ? this.checkoutInfo.use_paypwd : 0
			},
			use_paypwd_open() {
				return this.checkoutInfo.use_paypwd_open ? this.checkoutInfo.use_paypwd_open : 0
			},
			paypwdValue: {
				get() {
					return this.$store.state.common.trade_pwd
				},
				set(val) {
					this.$store.state.common.trade_pwd = val
				}
			},
			vipCard() {
				return this.checkoutInfo.use_membership_card > 0 ? this.checkoutInfo.membership_card_info : ''
			},
			//优惠券按店铺分割
			shopCouponList() {
				let dataArr = [];

				if (this.couponsList.length > 0) {
					this.couponsList.map((mapItem) => {
						if (dataArr.length == 0) {
							dataArr.push({
								ru_id: mapItem.ru_id,
								list: [mapItem]
							})
						} else {
							let res = dataArr.some((item) => {
								//判断相同的店铺，有就添加到当前项
								if (item.ru_id == mapItem.ru_id) {
									item.list.push(mapItem)
									return true
								}
							})
							if (!res) {
								//如果没找相同的部门添加一个新对象
								dataArr.push({
									ru_id: mapItem.ru_id,
									list: [mapItem]
								})
							}
						}
					})
				}
				return dataArr
			},
			
			// 店铺维度优惠券结构重组
			// shopCouponList() {
			//     let dataArr = [];
			//     this.couponsList.forEach(coupon => {
			//         // 使用find代替some以提升性能
			//         const existShop = dataArr.find(item => item.ru_id === coupon.ru_id);
			//         existShop ? existShop.list.push(coupon) 
			//                  : dataArr.push({ ru_id: coupon.ru_id, list: [coupon] });
			//     });
			//     return dataArr;
			// },
			cardCount: function() {
				if (this.valueCartInfo.card_list) {
					if (this.currTab == 0) {
						return this.valueCartInfo.use_card_count || 0
					} else {
						return this.valueCartInfo.not_use_card_count || 0
					}
				} else {
					return 0
				}
			}
		},
		methods: {
			collectCurrentPaymentOption() {
				if (!this.pay_id) {
					return null;
				}
				const matched = Array.isArray(this.payment_method) && this.payment_method.find(item => item.pay_id === this.pay_id);
				if (matched) {
					return {
						pay_id: matched.pay_id,
						pay_name: matched.pay_name,
						pay_code: matched.pay_code,
						use_list: matched.use_list || {}
					};
				}
				return {
					pay_id: this.pay_id,
					pay_name: this.pay_name,
					pay_code: this.pay_code,
					use_list: {}
				};
			},
			lockBalanceToggle(reason = '') {
				this.balanceToggleDisabled = true;
				this.balanceToggleDisabledReason = reason || '已自动选择支付方式';
				this.balancePaymentActive = false;
				this.use_surplus_val = 0;
				this.balance_money = 0;
			},
			unlockBalanceToggle() {
				this.balanceToggleDisabled = false;
				this.balanceToggleDisabledReason = '';
			},
			lockCreditToggle(reason = '') {
				this.creditToggleDisabled = true;
				this.creditToggleDisabledReason = reason || '已自动选择支付方式';
				this.use_credit_val = 0;
				this.surplus_credit_line = 0;
			},
			unlockCreditToggle() {
				this.creditToggleDisabled = false;
				this.creditToggleDisabledReason = '';
			},
			rememberLastNonBalancePayment(option) {
				if (!option || option.pay_name === this.balancePaymentLabel) {
					return;
				}
				this.lastNonBalancePayment = {
					pay_id: option.pay_id,
					pay_name: option.pay_name,
					pay_code: option.pay_code,
					use_list: option.use_list || {}
				};
			},
			getBalancePaymentOption() {
				if (!Array.isArray(this.payment_method) || this.payment_method.length === 0) {
					return null;
				}
				return this.payment_method.find(item =>
					item.pay_name === this.balancePaymentLabel || item.pay_id === 11
				) || null;
			},
			findFirstNonBalancePayment() {
				if (!Array.isArray(this.payment_method) || this.payment_method.length === 0) {
					return null;
				}
				return this.payment_method.find(item => item.pay_name !== this.balancePaymentLabel) || null;
			},
			getFallbackPaymentOption() {
				if (this.lastNonBalancePayment) {
					return this.lastNonBalancePayment;
				}
				return this.findFirstNonBalancePayment();
			},
			initializeShopGoodsCollapsed(list = null) {
				const source = Array.isArray(list) ? list : this.processedGoodsList || [];
				if (!Array.isArray(source)) {
					this.shopGoodsCollapsed = [];
					return;
				}
				const nextState = source.map((_, idx) => {
					if (typeof this.shopGoodsCollapsed[idx] === 'boolean') {
						return this.shopGoodsCollapsed[idx];
					}
					return true;
				});
				this.shopGoodsCollapsed = nextState;
			},
			isShopGoodsCollapsed(index) {
				if (!Array.isArray(this.shopGoodsCollapsed)) {
					return true;
				}
				const state = this.shopGoodsCollapsed[index];
				return typeof state === 'boolean' ? state : true;
			},
			getShopGoodsForDisplay(goods, index) {
				const filtered = this.filteredItems(goods);
				const collapsed = this.isShopGoodsCollapsed(index);
				if (collapsed && filtered.length > this.visibleGoodsLimit) {
					return filtered.slice(0, this.visibleGoodsLimit);
				}
				return filtered;
			},
			hasMoreGoods(item) {
				if (!item || !Array.isArray(item.goods)) {
					return false;
				}
				const filtered = this.filteredItems(item.goods);
				return filtered.length > this.visibleGoodsLimit;
			},
			toggleShopGoods(index) {
				const current = this.isShopGoodsCollapsed(index);
				this.$set(this.shopGoodsCollapsed, index, !current);
			},
			toggleBalancePayment(enabled, options = {}) {
				const {
					silent = false
				} = options;

				const prevState = {
					balancePaymentActive: this.balancePaymentActive,
					use_surplus_val: this.use_surplus_val,
					use_credit_val: this.use_credit_val,
					balance_money: this.balance_money,
					surplus_credit_line: this.surplus_credit_line,
					balance_money_available: this.balance_money_available,
					surplus_credit_line_available: this.surplus_credit_line_available,
					pay_id: this.pay_id,
					pay_name: this.pay_name,
					pay_code: this.pay_code,
					submit_pay_id: this.submit_pay_id,
					submit_pay_code: this.submit_pay_code,
					payDisplayName: this.payDisplayName,
					princeType: this.princeType,
					payment_info: {
						...this.payment_info
					}
				};

				if (enabled) {
					const balanceOption = this.getBalancePaymentOption();
					if (!balanceOption) {
						if (!silent) {
							uni.showToast({
								title: this.$t ? this.$t('lang.payment_method_not_installed') : '暂无可用支付方式',
								icon: 'none'
							});
						}
						return false;
					}

					if (!prevState.balancePaymentActive && this.pay_id) {
						const currentOption = this.collectCurrentPaymentOption();
						if (currentOption) {
							this.rememberLastNonBalancePayment(currentOption);
						}
					}

					this.balance_money_available = balanceOption.use_list && balanceOption.use_list.money ?
						Number(balanceOption.use_list.money) : 0;
					this.surplus_credit_line_available = balanceOption.use_list && balanceOption.use_list.surplus_credit_line ?
						Number(balanceOption.use_list.surplus_credit_line) : 0;

					this.balancePaymentActive = true;
					this.use_surplus_val = 1;
					this.balance_money = this.balance_money_available;
					this.surplus_credit_line = this.use_credit_val === 1 ? this.surplus_credit_line_available : 0;

					const success = this.applyBalancePaymentState({
						silent
					});

					if (!success) {
						this.balancePaymentActive = prevState.balancePaymentActive;
						this.use_surplus_val = prevState.use_surplus_val;
						this.use_credit_val = prevState.use_credit_val;
						this.balance_money = prevState.balance_money;
						this.surplus_credit_line = prevState.surplus_credit_line;
						this.balance_money_available = prevState.balance_money_available;
						this.surplus_credit_line_available = prevState.surplus_credit_line_available;
						this.pay_id = prevState.pay_id;
						this.pay_name = prevState.pay_name;
						this.pay_code = prevState.pay_code;
						this.submit_pay_id = prevState.submit_pay_id;
						this.submit_pay_code = prevState.submit_pay_code;
						this.payDisplayName = prevState.payDisplayName;
						this.princeType = prevState.princeType;
						this.payment_info = {
							...prevState.payment_info
						};
						return false;
					}

					// 【关键修复】余额/信用付开启成功后，调用后端 changesurplus 接口同步金额
					// 使用 surplusvValHandle 统一处理 total.surplus、surplus_formated 和 amount
					try {
						this.surplusvValHandle();
					} catch (err) {
						// 静默处理错误
					}

					return true;
				}

				this.balancePaymentActive = false;
				this.use_surplus_val = 0;
				this.balance_money = 0;
				this.use_credit_val = 0; // 【关键修复】关闭余额时，同时关闭信用付，确保状态一致
				this.surplus_credit_line = 0;

				if (!prevState.balancePaymentActive) {
					return true;
				}

				const fallbackOption = this.getFallbackPaymentOption();
				if (!fallbackOption) {
					if (!silent) {
						uni.showToast({
							title: this.$t ? this.$t('lang.payment_method_not_installed') : '暂无其他支付方式',
							icon: 'none'
						});
					}
					this.balancePaymentActive = prevState.balancePaymentActive;
					this.use_surplus_val = prevState.use_surplus_val;
					this.use_credit_val = prevState.use_credit_val;
					this.balance_money = prevState.balance_money;
					this.surplus_credit_line = prevState.surplus_credit_line;
					this.pay_id = prevState.pay_id;
					this.pay_name = prevState.pay_name;
					this.pay_code = prevState.pay_code;
					this.submit_pay_id = prevState.submit_pay_id;
					this.submit_pay_code = prevState.submit_pay_code;
					this.payDisplayName = prevState.payDisplayName;
					this.princeType = prevState.princeType;
					this.payment_info = {
						...prevState.payment_info
					};
					return false;
				}

				this.pay_id = fallbackOption.pay_id;
				this.pay_name = fallbackOption.pay_name;
				this.pay_code = fallbackOption.pay_code;
				this.submit_pay_id = fallbackOption.pay_id;
				this.submit_pay_code = fallbackOption.pay_code;
				this.payDisplayName = fallbackOption.pay_name;
				
				// 【关键修复】计算正确的原始金额（商品价格 + 运费 - 优惠券），不使用this.total.amount（可能是旧值）
				const latestTotal = this.checkoutInfo && this.checkoutInfo.total ? this.checkoutInfo.total : this.total;
				const goodsPrice = latestTotal && latestTotal.goods_price ? Number(latestTotal.goods_price) : 0;
				const shippingFee = this.shippingFee ? Number(this.shippingFee) : 0;
				const couponsMoney = Number(this.couponsObject && this.couponsObject.couponsMoney ? this.couponsObject.couponsMoney : 0);
				const resetAmountSource = this.moneyPrecision(goodsPrice + shippingFee - couponsMoney);
				
				this.resetPaymentStatus(resetAmountSource);
				this.princeType = false;
				
				// 【关键修复】关闭余额时，调用后端 changesurplus 接口获取关闭后的价格
				// 因为 balance_money 已设为 0，surplusvValHandle 会传递 surplus: 0 给后端
				// 使用 $nextTick 确保状态更新后再调用，避免传递错误的参数
				this.$nextTick(() => {
					try {
						this.surplusvValHandle();
					} catch (err) {
						// 静默处理错误
					}
				});
				
				return true;
			},
			applyBalancePaymentState(options = {}) {
				const {
					silent = false
				} = options;

				const prevState = {
					pay_id: this.pay_id,
					pay_name: this.pay_name,
					pay_code: this.pay_code,
					submit_pay_id: this.submit_pay_id,
					submit_pay_code: this.submit_pay_code,
					payDisplayName: this.payDisplayName,
					princeType: this.princeType,
					payment_info: {
						...this.payment_info
					}
				};

				const balanceOption = this.getBalancePaymentOption();
				if (!balanceOption) {
					return false;
				}

				const balanceLabel = this.use_credit_val === 1 ? this.balancePaymentLabel : '余额';

				// 【关键修复】按照优先级顺序计算：储值卡 → 余额 → 先用后付
				// 1. 先计算应付款（商品金额 + 运费 - 优惠券 - 折扣 - 红包 - 积分）
				// 【关键】计算只用商品金额 goods_price，不用 total.amount（total.amount 仅用于展示）
				let baseAmount = 0;
				const latestTotalForApply = this.checkoutInfo && this.checkoutInfo.total ? this.checkoutInfo.total : this.total;
				const goodsPrice = this.moneyPrecision(parseFloat(latestTotalForApply && latestTotalForApply.goods_price ? latestTotalForApply.goods_price : 0) || 0);
				if (goodsPrice > 0) {
					baseAmount = goodsPrice;
				} else if (this.price && this.price > 0) {
					baseAmount = this.moneyPrecision(parseFloat(this.price) || 0);
				}
				const shippingFee = this.shippingFee ? Number(this.shippingFee) : 0;
				const couponsMoney = Number(this.couponsObject && this.couponsObject.couponsMoney ? this.couponsObject.couponsMoney : 0);
				const discount = Number(latestTotalForApply && latestTotalForApply.discount) || 0;
				const bonusMoney = Number(latestTotalForApply && latestTotalForApply.bonus_money) || Number(this.bonusObject && this.bonusObject.bonusMoney) || 0;
				const integralMoney = Number(latestTotalForApply && latestTotalForApply.integral_money) || 0;
				let totalAmount = baseAmount + shippingFee - couponsMoney - discount - bonusMoney - integralMoney;
				if (totalAmount < 0) {
					totalAmount = 0;
				}
				totalAmount = this.moneyPrecision(totalAmount);
				
				// 2. 计算储值卡扣款（优先级最高，优先后端返回值）
				const valueCardMoney = this.getValueCardMoney();
				const amountAfterValueCard = this.moneyPrecision(Math.max(0, totalAmount - valueCardMoney));
				
				// 3. 基于（应付款 - 储值卡扣款）计算余额和先用后付扣款
				let originalPrice = amountAfterValueCard;
				let remainingAfterCredit = 0;
				// 【修复】确保在按钮状态正确时才计算 payment_info
				if (this.total && this.total.amount !== undefined) {
					// 只有在 balancePaymentActive 为 true 时才计算
					if (this.balancePaymentActive) {
					remainingAfterCredit = this.calculateBalanceCreditPayment(originalPrice);
				} else {
						// 如果按钮关闭，重置 payment_info
						this.resetPaymentStatus(originalPrice);
						remainingAfterCredit = originalPrice;
					}
				} else {
					// 如果 total.amount 为 undefined，重置 payment_info
					this.resetPaymentStatus(0);
					remainingAfterCredit = 0;
				}

				const fallbackOption = this.getFallbackPaymentOption();

				if (remainingAfterCredit > 0) {
					if (!fallbackOption) {
						if (!silent) {
							uni.showToast({
								title: this.$t ? this.$t('lang.payment_method_not_installed') : '暂无其他支付方式',
								icon: 'none'
							});
						}
						this.pay_id = prevState.pay_id;
						this.pay_name = prevState.pay_name;
						this.pay_code = prevState.pay_code;
						this.submit_pay_id = prevState.submit_pay_id;
						this.submit_pay_code = prevState.submit_pay_code;
						this.payDisplayName = prevState.payDisplayName;
						this.princeType = prevState.princeType;
						this.payment_info = {
							...prevState.payment_info
						};
						return false;
					}

					this.pay_id = fallbackOption.pay_id;
					this.pay_name = fallbackOption.pay_name;
					this.pay_code = fallbackOption.pay_code;
					this.submit_pay_id = fallbackOption.pay_id;
					this.submit_pay_code = fallbackOption.pay_code;
					this.payDisplayName = `${fallbackOption.pay_name}`;
					this.rememberLastNonBalancePayment(fallbackOption);
				} else {
					this.pay_id = balanceOption.pay_id;
					this.pay_name = balanceOption.pay_name;
					this.pay_code = balanceOption.pay_code;
					this.submit_pay_id = balanceOption.pay_id;
					this.submit_pay_code = balanceOption.pay_code;
					this.payDisplayName = balanceLabel;
				}

				this.princeType = !!(this.checkoutInfo.surplus_credit_line_tip && this.payment_info.used_credit > 0);
				return true;
			},
			toggleCreditPayment(enabled, options = {}) {
				const {
					silent = false
				} = options;

				const prevState = {
					use_credit_val: this.use_credit_val,
					surplus_credit_line: this.surplus_credit_line,
					pay_id: this.pay_id,
					pay_name: this.pay_name,
					pay_code: this.pay_code,
					submit_pay_id: this.submit_pay_id,
					submit_pay_code: this.submit_pay_code,
					payDisplayName: this.payDisplayName,
					princeType: this.princeType,
					payment_info: {
						...this.payment_info
					}
				};

				if (enabled) {
					// 如果余额值大于0，用后付需要跟随余额开启；如果余额值小于等于0，用后付可以独立开启
					if (!this.balancePaymentActive && this.balance_money_available > 0) {
						if (!silent) {
							uni.showToast({
								title: '请先开启余额',
								icon: 'none'
							});
						}
						return false;
					}

					if (this.surplus_credit_line_available <= 0) {
						if (!silent) {
							uni.showToast({
								title: this.$t ? this.$t('lang.payment_method_not_installed') : '暂无可用额度',
								icon: 'none'
							});
						}
						return false;
					}

					this.use_credit_val = 1;
					// 【关键修复】移除设置surplus_credit_line的初始值，让applyBalancePaymentState和surplusvValHandle来计算正确的值
					// this.surplus_credit_line = this.surplus_credit_line_available;

					const success = this.applyBalancePaymentState({
						silent
					});

					if (!success) {
						this.use_credit_val = prevState.use_credit_val;
						this.surplus_credit_line = prevState.surplus_credit_line;
						this.pay_id = prevState.pay_id;
						this.pay_name = prevState.pay_name;
						this.pay_code = prevState.pay_code;
						this.submit_pay_id = prevState.submit_pay_id;
						this.submit_pay_code = prevState.submit_pay_code;
						this.payDisplayName = prevState.payDisplayName;
						this.princeType = prevState.princeType;
						this.payment_info = {
							...prevState.payment_info
						};
						return false;
					}

					// 【关键修复】先用后付开启成功后，调用后端 changesurplus 接口同步金额
					// 使用 surplusvValHandle 统一处理 total.surplus、surplus_formated 和 amount
					// 参数会根据 balancePaymentActive 和实际使用的余额/信用付金额自动传递
					try {
						this.surplusvValHandle();
					} catch (err) {
						// 静默处理错误
					}

					return true;
				}

				this.use_credit_val = 0;
				this.surplus_credit_line = 0;

				if (!this.balancePaymentActive) {
					// 【关键修复】如果余额未开启，关闭信用付时不需要再次调用接口
					// 因为关闭余额时（toggleBalancePayment）已经调用过 surplusvValHandle 了
					// 避免重复调用导致传递错误的参数
					return true;
				}

				const success = this.applyBalancePaymentState({
					silent
				});

				if (!success) {
					this.use_credit_val = prevState.use_credit_val;
					this.surplus_credit_line = prevState.surplus_credit_line;
					this.pay_id = prevState.pay_id;
					this.pay_name = prevState.pay_name;
					this.pay_code = prevState.pay_code;
					this.submit_pay_id = prevState.submit_pay_id;
					this.submit_pay_code = prevState.submit_pay_code;
					this.payDisplayName = prevState.payDisplayName;
					this.princeType = prevState.princeType;
					this.payment_info = {
						...prevState.payment_info
					};
					return false;
				}

				// 【关键修复】关闭信用付时，调用后端 changesurplus 接口获取关闭后的价格
				// 因为 surplus_credit_line 已设为 0，但 balance_money 可能还在使用
				// surplusvValHandle 会根据当前 balance_money 传递正确的 surplus 值
				try {
					this.surplusvValHandle();
				} catch (err) {
					// 静默处理错误
				}

				return true;
			},
			ensurePaymentPriority() {
				if (!this.total || this.total === '') {
					return;
				}

				// 【关键】计算只用商品金额 goods_price，不用 total.amount（total.amount 仅用于展示）
				const latestTotalForPriority = this.checkoutInfo && this.checkoutInfo.total ? this.checkoutInfo.total : this.total;
				const goodsPricePriority = this.moneyPrecision(parseFloat(latestTotalForPriority && latestTotalForPriority.goods_price ? latestTotalForPriority.goods_price : 0) || 0);
				let baseAmount = goodsPricePriority > 0 ? goodsPricePriority : (this.price && this.price > 0 ? this.moneyPrecision(parseFloat(this.price) || 0) : 0);
				const shippingFee = this.shippingFee ? Number(this.shippingFee) : 0;
				const couponsMoney = Number(this.couponsObject && this.couponsObject.couponsMoney ? this.couponsObject.couponsMoney : 0);
				const discountPriority = Number(latestTotalForPriority && latestTotalForPriority.discount) || 0;
				const bonusMoneyPriority = Number(latestTotalForPriority && latestTotalForPriority.bonus_money) || Number(this.bonusObject && this.bonusObject.bonusMoney) || 0;
				const integralMoneyPriority = Number(latestTotalForPriority && latestTotalForPriority.integral_money) || 0;
				let amountBeforeValueCard = baseAmount + shippingFee - couponsMoney - discountPriority - bonusMoneyPriority - integralMoneyPriority;
				if (amountBeforeValueCard < 0) {
					amountBeforeValueCard = 0;
				}
				amountBeforeValueCard = this.moneyPrecision(amountBeforeValueCard);
				
				const selectedCardId = Number(this.valueCardObject && this.valueCardObject.valueCardId ? this.valueCardObject.valueCardId : 0);
				const hasValueCardSelected = selectedCardId > 0;
				
				// 储值卡扣款：优先后端返回值
				let valueCardMoney = 0;
				if (hasValueCardSelected) {
					valueCardMoney = this.getValueCardMoney();
					// 同步展示（若后端有返回则已在接口回调中赋值）
					if (this.valueCardObject.valueCardMoney !== valueCardMoney) {
						this.valueCardObject.valueCardMoney = valueCardMoney;
						this.valueCardObject.valueCardContent = this.currency + this.formatCurrencyValue(valueCardMoney);
					}
				}
				
				// 【关键修复】计算剩余需要支付的金额（应付款 - 储值卡扣款）
				// 这是余额和先用后付需要支付的金额
				let amountDue = amountBeforeValueCard - valueCardMoney;
				if (amountDue < 0) {
					amountDue = 0;
				}
				amountDue = this.moneyPrecision(amountDue);
				const hasValueCardList = this.valueCartInfo && Array.isArray(this.valueCartInfo.card_list) && this.valueCartInfo.card_list.length > 0;
				const canUseBalance = this.checkoutInfo && this.checkoutInfo.use_surplus > 0;
				const valueCardDataReady = this.valueCardLoaded || hasValueCardSelected;
				
			// 【优化】即使 prioritySelectingValueCard 为 true（正在等待 changecard API），也先显示按钮
			// 这样可以避免用户看到明显的等待时间，按钮会先显示为关闭状态，等计算完成后再开启
			if (!valueCardDataReady) {
				return;
			}
			
			// 【优化】如果正在等待 changecard API，先显示按钮（关闭状态），不阻塞显示
			// 等 changecard 返回后，会再次调用 ensurePaymentPriority，此时再根据计算结果开启按钮
			if (this.prioritySelectingValueCard) {
				// 先显示按钮，但保持关闭状态
				this.initializingPaymentToggles = false;
				return;
			}

			// 【关键修复】如果用户明确取消了储值卡，不再自动应用
			// 【关键修复】selectedCardId 应该考虑 tempValueCardId（当弹窗打开时）或 valueCardObject.valueCardId（当弹窗关闭时）
			const actualSelectedCardId = this.valueCardObject.valueCardBase ? this.tempValueCardId : selectedCardId;
			if (!hasValueCardSelected && hasValueCardList && actualSelectedCardId <= 0 && !this.prioritySelectingValueCard && !this.userValueCardCancelled) {
				const bestCard = this.findBestValueCard(amountDue);
				// 【关键修复】比较时也应该考虑 tempValueCardId
				const currentCardId = this.valueCardObject.valueCardBase ? this.tempValueCardId : this.valueCardObject.valueCardId;
				if (bestCard && currentCardId !== bestCard.vid) {
					this.pendingValueCardApplyId = Number(bestCard.vid) || 0;
					this.prioritySelectingValueCard = true;
					this.tryApplyPendingValueCard();
					return;
				}
			}

			this.unlockBalanceToggle();
			this.unlockCreditToggle();

			// 【关键修复】优先检查储值卡是否完全覆盖，如果完全覆盖，直接处理并返回，不进行余额/信用付的自动开启判断
			// 这样可以避免余额按钮先开启再关闭的闪烁问题
			if (hasValueCardSelected && amountDue <= 0) {
				if (this.balancePaymentActive) {
					this.toggleCreditPayment(false, {
						silent: true
					});
					this.toggleBalancePayment(false, {
						silent: true
					});
				}
				this.lockBalanceToggle('已使用储值卡完成支付');
				this.lockCreditToggle('已使用储值卡完成支付');
				this.$nextTick(() => {
					this.surplusSelf = false;
					this.creditSelf = false;
					this.balanceSwitchVersion++;
					this.creditSwitchVersion++;
				});
				this.autoPriorityApplied = true;
				this.initializingPaymentToggles = false;
				return;
			}

			// 【修复】智能判断是否应该自动开启（只有在储值卡不能完全覆盖时才计算）
			// 如果价格满足条件（amountDue > 0 且有可用余额/信用付），即使 userBalanceModified 为 true，也应该考虑自动开启
			// 但需要检查是否真的满足条件
			const shouldAutoBalance = !this.userBalanceModified || 
				(amountDue > 0 && this.balance_money_available > 0 && !this.balancePaymentActive);
			const shouldAutoCredit = !this.userCreditModified || 
				(amountDue > 0 && this.surplus_credit_line_available > 0 && this.use_credit_val !== 1 && 
				 (this.balancePaymentActive || this.balance_money_available <= 0));

			// 【修复】提前返回逻辑：即使 shouldAutoCredit 为 false，如果余额已开启或有剩余金额，也应该继续检查信用付
			// 只有在完全不需要处理余额和信用付的情况下才提前返回
			// 如果余额值大于0，用后付需要跟随余额开启；如果余额值小于等于0，用后付可以独立启用
			const canUseCreditIndependently = this.balance_money_available <= 0;
			const needsBalanceCheck = shouldAutoBalance && canUseBalance && amountDue > 0 && !this.balancePaymentActive;
			const needsCreditCheck = (this.balancePaymentActive || canUseCreditIndependently) && amountDue > 0 && this.surplus_credit_line_available > 0;
			
			if (this.autoPriorityApplied && !needsBalanceCheck && !needsCreditCheck && !shouldAutoCredit) {
					return;
				}

				if (shouldAutoBalance && canUseBalance && amountDue > 0 && !this.balancePaymentActive) {
					const success = this.toggleBalancePayment(true, {
						silent: true
					});
					if (!success) {
						this.autoPriorityApplied = true;
						return;
					}
				}

				// 【修复】确保 payment_info 的计算与按钮状态同步
				// 如果 balancePaymentActive 为 true，无论 shouldAutoBalance 如何，都需要计算 payment_info
				if (this.balancePaymentActive) {
					// 确保 use_surplus_val 与 balancePaymentActive 同步
					if (this.use_surplus_val === 0) {
						this.use_surplus_val = 1;
					}
					const applyResult = this.applyBalancePaymentState({
						silent: true
					});
				} else {
					// 【修复】如果按钮关闭，确保 payment_info 被重置
					if (this.payment_info && (this.payment_info.used_balance > 0 || this.payment_info.used_credit > 0)) {
						const resetAmountSource = this.total && this.total.amount !== undefined ? this.total.amount : (this.payment_info.original_price || 0);
						this.resetPaymentStatus(resetAmountSource);
					}
				}

				const remainingAfterBalance = this.moneyPrecision(
					this.payment_info && this.payment_info.remaining_debt !== undefined ? this.payment_info.remaining_debt : amountDue
				);

			// 【修复】即使 shouldAutoCredit 为 false，如果余额已开启或有剩余金额，也应该考虑自动开启信用付
			const shouldAutoEnableCredit = (this.balancePaymentActive || canUseCreditIndependently) && 
				(shouldAutoCredit || ((this.balancePaymentActive || canUseCreditIndependently) && remainingAfterBalance > 0 && this.surplus_credit_line_available > 0));

				// 【修复】确保信用付状态与 payment_info 同步
				if (shouldAutoEnableCredit) {
					if (remainingAfterBalance > 0 && this.surplus_credit_line_available > 0) {
						if (this.use_credit_val !== 1) {
						// 【关键修复】即使 userCreditModified 为 true，如果价格满足条件，也应该自动开启
						// 重置 userCreditModified 标记，允许自动开启（支持独立使用信用付的情况）
						if (this.userCreditModified && (this.balancePaymentActive || canUseCreditIndependently) && remainingAfterBalance > 0) {
							this.userCreditModified = false;
						}
							const creditSuccess = this.toggleCreditPayment(true, {
								silent: true
							});
							if (creditSuccess) {
								// 【修复】确保 use_credit_val 与按钮状态同步
								// toggleCreditPayment 已经设置了 use_credit_val = 1，这里确保同步
								if (this.use_credit_val !== 1) {
									this.use_credit_val = 1;
								}
								// 【关键修复】移除applyBalancePaymentState调用，因为toggleCreditPayment已经通过surplusvValHandle更新了所有必要的值
								// 再次调用applyBalancePaymentState会覆盖surplusvValHandle计算出的正确值
								// this.applyBalancePaymentState({
								// 	silent: true
								// });
								// 【关键修复】确保 initializingPaymentToggles 为 false，否则开关会被强制显示为 false
								this.initializingPaymentToggles = false;
								// 【关键修复】直接设置 creditSelf = true，确保UI状态同步
								this.creditSelf = true;
								// 【关键修复】通过 $nextTick 确保视图更新
								this.$nextTick(() => {
									// 强制触发组件重新渲染
									this.creditSwitchVersion++;
								this.$forceUpdate();
							});
							}
						} else if (this.use_credit_val === 1) {
							// 【修复】如果 use_credit_val 已经是 1，但 payment_info 未更新，重新计算
							this.applyBalancePaymentState({
								silent: true
							});
						}
					} else if (this.use_credit_val === 1 && remainingAfterBalance <= 0) {
						// 【关键修复】如果剩余金额为 0，需要判断是否是因为余额+信用付完全覆盖了金额
						// 如果是完全覆盖（payment_info.used_credit > 0），说明信用付正在使用，不应该关闭
						// 只有在余额单独覆盖全部金额时（payment_info.used_credit === 0），才关闭信用付
						const isCreditBeingUsed = this.payment_info && this.payment_info.used_credit > 0;
						
						if (!isCreditBeingUsed) {
							// 余额单独覆盖全部金额，关闭信用付
						this.toggleCreditPayment(false, {
								silent: true
							});
							this.use_credit_val = 0;
						}
					}
			} else if ((this.balancePaymentActive || canUseCreditIndependently) && remainingAfterBalance > 0 && this.surplus_credit_line_available > 0) {
				// 【关键修复】即使 shouldAutoEnableCredit 为 false，如果余额已开启或可以独立使用信用付且有剩余金额，也应该检查是否需要开启信用付
				// 这种情况通常是因为 userCreditModified 为 true，但价格满足条件，应该自动开启
					if (this.use_credit_val !== 1) {
						// 重置 userCreditModified 标记，允许自动开启
						this.userCreditModified = false;
						const creditSuccess = this.toggleCreditPayment(true, {
							silent: true
						});
						if (creditSuccess) {
							// 【修复】确保 use_credit_val 与按钮状态同步
							// toggleCreditPayment 已经设置了 use_credit_val = 1，这里确保同步
							if (this.use_credit_val !== 1) {
								this.use_credit_val = 1;
							}
							this.applyBalancePaymentState({
								silent: true
							});
							// 【关键修复】确保 initializingPaymentToggles 为 false，否则开关会被强制显示为 false
							this.initializingPaymentToggles = false;
							// 【关键修复】直接设置 creditSelf = true，确保UI状态同步
							this.creditSelf = true;
							// 【关键修复】通过 $nextTick 确保视图更新
							this.$nextTick(() => {
								// 强制触发组件重新渲染
								this.creditSwitchVersion++;
								this.$forceUpdate();
							});
						}
					} else if (this.use_credit_val === 1) {
						// 重新计算 payment_info，确保与按钮状态同步
						this.applyBalancePaymentState({
							silent: true
						});
					}
				} else if (this.use_credit_val === 1 && this.balancePaymentActive) {
					// 【修复】如果 use_credit_val 为 1，但剩余金额为 0 或没有可用额度，需要检查是否需要更新 payment_info
					if (remainingAfterBalance > 0 && this.surplus_credit_line_available > 0) {
						// 重新计算 payment_info，确保与按钮状态同步
						this.applyBalancePaymentState({
							silent: true
						});
					}
				}

				// 【关键修复】只有在余额开启且余额值大于0，且余额单独覆盖全部金额时（信用付未使用），才禁用信用付按钮
				// 如果余额+信用付完全覆盖金额（payment_info.used_credit > 0），不应该禁用信用付按钮
				const isCreditBeingUsed = this.payment_info && this.payment_info.used_credit > 0;
				const shouldDisableCredit = this.balancePaymentActive && 
					this.balance_money_available > 0 && 
					remainingAfterBalance <= 0 && 
					!isCreditBeingUsed; // 只有在信用付未使用时才禁用
				
				if (shouldDisableCredit) {
					this.creditToggleDisabled = true;
					this.creditToggleDisabledReason = '已选择支付';
					this.$nextTick(() => {
						this.creditSelf = false;
						this.creditSwitchVersion++;
					});
				} else {
					this.creditToggleDisabled = false;
					this.creditToggleDisabledReason = '';
				}

				this.autoPriorityApplied = true;
				this.initializingPaymentToggles = false;
				
				// 如果有保存的支付状态，在数据准备好后恢复
				this.restoreSavedPaymentState();
			},
			restoreSavedPaymentState() {
				if (!this.savedPaymentState) {
					return;
				}
				
				// 确保数据已准备好
				if (!this.total || !this.valueCardLoaded) {
					// 延迟重试
					this.$nextTick(() => {
						setTimeout(() => {
							this.restoreSavedPaymentState();
						}, 200);
					});
					return;
				}
				
				const saved = this.savedPaymentState;
				
				// 恢复储值卡：优先后端 total.card_money，否则前端计算
				if (saved.valueCardId > 0) {
					this.valueCardObject.valueCardId = saved.valueCardId;
					const cardMoney = this.getValueCardMoney();
					this.valueCardObject.valueCardMoney = cardMoney;
					if (cardMoney > 0) {
						this.valueCardObject.valueCardContent = this.currency + this.formatCurrencyValue(cardMoney);
					} else {
						this.valueCardObject.valueCardContent = this.$t('lang.no_use_value_card');
					}
				}
				
				// 恢复余额/用后付状态
				if (saved.balancePaymentActive || saved.use_surplus_val > 0 || saved.use_credit_val > 0) {
					// 先恢复基础数据
					this.balance_money = saved.balance_money || 0;
					this.surplus_credit_line = saved.surplus_credit_line || 0;
					
					// 如果之前开启了余额/用后付，重新应用
					if (saved.balancePaymentActive) {
						this.use_surplus_val = saved.use_surplus_val || 0;
						this.use_credit_val = saved.use_credit_val || 0;
						
						// 重新应用支付状态
						const success = this.toggleBalancePayment(true, { silent: true });
						if (success && saved.use_credit_val > 0) {
							this.toggleCreditPayment(true, { silent: true });
						}
						
					}
				}
				
				// 清除保存的状态，避免重复恢复
				this.savedPaymentState = null;
			},
		
			  // 打开商家进货弹窗
