			    // 选择图片
			    async chooseImage(field) {
			        this.currentUploadField = field;
			        
			        // 检查是否已达最大上传数量（这里限制为1张）
			        if (this.merchantForm[field]) {
			            return uni.showToast({
			                title: '只能上传一张图片',
			                icon: 'none'
			            });
			        }
			
			        // #ifdef H5
			        this.handleImageSelection(field);
			        // #endif
			
			        // #ifndef H5
			        // 非H5平台检查权限
			        var result = await this.premissionCheck("CAMERA_EXTERNAL_STORAGE");
			        if (result == 1) {
			            this.handleImageSelection(field);
			        } else {
			            uni.showToast({
			                title: '请授予文件访问权限',
			                icon: 'none'
			            });
			        }
			        // #endif
			    },
			       // 权限检查方法（如果之前没有的话）
			        premissionCheck(permission) {
			            return new Promise((resolve) => {
			                // 这里实现您的权限检查逻辑
			                // 返回1表示有权限，0表示无权限
			                resolve(1); // 简化处理，实际需要根据平台实现
			            });
			        },
			    // 处理图片选择逻辑
			    handleImageSelection(field) {
			        let that = this;
			        uni.chooseImage({
			            count: 1, // 只选择一张
			            sizeType: ['original', 'compressed'],
			            success: (res) => {
			                const tempPath = res.tempFilePaths[0];
			                // 显示本地预览
			                that.merchantForm[field] = tempPath;
			                // 上传到服务器
			                that.uploadImage(tempPath, field);
			            }
			        });
			    },
			    
			    // 上传图片到服务器
			    async uploadImage(tempPath, field) {
			        let that = this;
			        uni.showLoading({
			            mask: true,
			            title: '上传中...'
			        });
			
			        try {
			            // #ifdef MP-WEIXIN
			            // 微信小程序检查图片大小并压缩
			            const fileInfo = await new Promise(resolve => {
			                uni.getFileInfo({
			                    filePath: tempPath,
			                    success: resolve
			                });
			            });
			
			            const maxSize = 1024 * 1024 * 5; // 最大5MB
			            if (fileInfo.size > maxSize) {
			                tempPath = await new Promise(resolve => {
			                    uni.compressImage({
			                        src: tempPath,
			                        quality: 60,
			                        success: (result) => resolve(result.tempFilePath)
			                    });
			                });
			            }
			            // #endif
			
			            // 转换为base64并上传
			            const base64 = await pathToBase64(tempPath);
			            const uploadResult = await this.$store.dispatch('setMaterial', {
			                file: {
			                    content: base64
			                },
			                type: 'merchant' // 商家文件类型
			            });
			
			            if (uploadResult.status === 'success' && uploadResult.data.length > 0) {
			                // 上传成功，更新对应的字段
			                const imageUrl = uploadResult.data[0];
			                that.merchantForm[field] = imageUrl;
			                
			                uni.showToast({
			                    title: '上传成功',
			                    icon: 'success'
			                });
			            } else {
			                uni.showToast({
			                    title: '上传失败',
			                    icon: 'none'
			                });
			                // 上传失败，清除本地预览
			                that.merchantForm[field] = '';
			            }
			        } catch (error) {
			            uni.showToast({
			                title: '上传失败',
			                icon: 'none'
			            });
			            that.merchantForm[field] = '';
			        } finally {
			            uni.hideLoading();
			        }
			    },
			      // 商家进货选中后的回调
			        onBusinessSelected() {
			            // 可以在这里处理商家进货选中后的业务逻辑
			        },
			        
			        // 个人使用选中后的回调
