			     moneyPrecision(value) {
			        return Number(Number(value).toFixed(2));
			      },
			  formatCurrencyValue(value) {
			    if (value === undefined || value === null || value === '') {
			      return '0.00';
			    }
			    const num = Number(value);
			    if (isNaN(num)) {
			      return '0.00';
			    }
			    return num.toFixed(2);
			  },
			  // 储值卡扣款金额：优先使用后端返回值（total.card_money），无返回或未选卡时用前端计算兜底
			  getValueCardMoney() {
			    const total = this.checkoutInfo && this.checkoutInfo.total ? this.checkoutInfo.total : this.total;
			    const currentCardId = Number(this.valueCardObject && this.valueCardObject.valueCardId ? this.valueCardObject.valueCardId : 0);
			    const backendCardId = Number(total && total.value_card_id ? total.value_card_id : 0);
			    if (currentCardId > 0 && backendCardId === currentCardId && total && total.card_money != null && total.card_money !== '') {
			      return this.moneyPrecision(Number(total.card_money) || 0);
			    }
			    return this.calculateValueCardMoney();
			  },
			  // 前端计算储值卡扣款（仅在后端未返回时兜底）
			  calculateValueCardMoney() {
			    if (!this.valueCardObject || !this.valueCardObject.valueCardId || this.valueCardObject.valueCardId <= 0) {
			      return 0;
			    }
			    return this.calculateValueCardMoneyByCardId(this.valueCardObject.valueCardId);
			  },
			  // 【关键修复】基于指定的 cardId 计算储值卡扣款金额
			  // 用于在用户关闭弹窗后，基于已确认的 checkoutInfo.total.value_card_id 计算
			  // 而不是基于弹窗中临时修改的 valueCardObject.valueCardId
			  calculateValueCardMoneyByCardId(cardId) {
			    const targetCardId = Number(cardId) || 0;
			    if (targetCardId <= 0) {
			      return 0;
			    }
			    
			    // 计算实际需要支付的金额（商品金额 + 运费 - 优惠券 - 折扣 - 红包 - 积分），只用商品金额不用 total.amount
			    const latestTotalForValueCard = this.checkoutInfo && this.checkoutInfo.total ? this.checkoutInfo.total : this.total;
			    const goodsPriceVC = this.moneyPrecision(parseFloat(latestTotalForValueCard && latestTotalForValueCard.goods_price ? latestTotalForValueCard.goods_price : 0) || 0);
			    let baseAmount = goodsPriceVC > 0 ? goodsPriceVC : (this.price && this.price > 0 ? this.moneyPrecision(parseFloat(this.price) || 0) : 0);
			    const shippingFee = this.shippingFee ? Number(this.shippingFee) : 0;
			    const couponsMoney = Number(this.couponsObject && this.couponsObject.couponsMoney ? this.couponsObject.couponsMoney : 0);
			    const discountVC = Number(latestTotalForValueCard && latestTotalForValueCard.discount) || 0;
			    const bonusMoneyVC = Number(latestTotalForValueCard && latestTotalForValueCard.bonus_money) || Number(this.bonusObject && this.bonusObject.bonusMoney) || 0;
			    const integralMoneyVC = Number(latestTotalForValueCard && latestTotalForValueCard.integral_money) || 0;
			    let amountBeforeValueCard = baseAmount + shippingFee - couponsMoney - discountVC - bonusMoneyVC - integralMoneyVC;
			    if (amountBeforeValueCard < 0) {
			      amountBeforeValueCard = 0;
			    }
			    amountBeforeValueCard = this.moneyPrecision(amountBeforeValueCard);
			    
			    // 获取储值卡可用余额
			    let valueCardAvailableBalance = 0;
			    if (this.checkoutInfo && this.checkoutInfo.value_card) {
			      const selectedCard = this.checkoutInfo.value_card.find(card => Number(card.vid) === targetCardId);
			      if (selectedCard) {
			        valueCardAvailableBalance = Number(selectedCard.card_money || 0);
			      }
			    }
			    
			    // 如果储值卡余额足够，使用实际需要支付的金额作为扣款金额
			    // 如果储值卡余额不足，使用储值卡可用余额
			    const actualValueCardMoney = valueCardAvailableBalance >= amountBeforeValueCard ? amountBeforeValueCard : valueCardAvailableBalance;
			    const finalValueCardMoney = this.moneyPrecision(actualValueCardMoney);
			    
			    return finalValueCardMoney;
			  },
			  // 在方法中应用精度处理
			  // 【关键修复】priceStr 应该是（应付款 - 储值卡扣款），确保按照优先级顺序计算
			  calculateBalanceCreditPayment(priceStr) {
			    // priceStr 已经是扣除储值卡后的金额
			    const originalPrice = this.moneyPrecision(parseFloat(priceStr) || 0);
			    
			    // 只有在余额/先用后付开启时才计算
			    if (!this.balancePaymentActive) {
			      this.payment_info = {
			        original_price: originalPrice,
			        used_balance: 0,
			        used_credit: 0,
			        remaining_debt: originalPrice,
			        adjusted_price: originalPrice
			      };
			      return originalPrice;
			    }
			    
			    const availableBalance = this.moneyPrecision(Math.max(this.balance_money_available, 0));
			    const availableCredit = this.moneyPrecision(Math.max(this.surplus_credit_line_available, 0));

			    // 先使用余额（优先级：余额 → 先用后付）
			    const usedBalance = Math.min(availableBalance, originalPrice);
			    const remainingAfterBalance = this.moneyPrecision(originalPrice - usedBalance);

			    // 再使用先用后付（基于剩余金额）
			    // 【关键修复】如果payment_info.used_credit已存在且正确，优先使用它（避免覆盖surplusvValHandle计算的值）
			    let usedCredit = 0;
			    if (this.use_credit_val === 1) {
					if (this.payment_info && this.payment_info.used_credit && Number(this.payment_info.used_credit) > 0) {
						// 如果payment_info.used_credit已存在，检查它是否合理（不超过可用额度和剩余金额）
						const existingCredit = Number(this.payment_info.used_credit);
						if (existingCredit <= availableCredit && existingCredit <= remainingAfterBalance) {
							usedCredit = this.moneyPrecision(existingCredit);
						} else {
							// 如果已存在的值不合理，重新计算
							usedCredit = this.moneyPrecision(Math.min(availableCredit, remainingAfterBalance));
						}
					} else {
						// 如果不存在，重新计算
						usedCredit = this.moneyPrecision(Math.min(availableCredit, remainingAfterBalance));
					}
				}
			    const remainingAfterCredit = this.moneyPrecision(remainingAfterBalance - usedCredit);

			    this.pay_yue_full = false;
			    this.pay_yue_credit = false;
			    this.pay_surplus = false;
			    this.pay_no = false;

			    // 更新余额和先用后付的实际使用金额
			    this.balance_money = this.moneyPrecision(usedBalance);
			    this.surplus_credit_line = this.use_credit_val === 1 ? this.moneyPrecision(usedCredit) : 0;
			    
			    this.payment_info = {
			      original_price: originalPrice,
			      used_balance: this.moneyPrecision(usedBalance),
			      used_credit: this.moneyPrecision(usedCredit),
			      remaining_debt: remainingAfterCredit,
			      adjusted_price: remainingAfterCredit
			    };

			    if (remainingAfterCredit === 0) {
			      if (usedBalance > 0 && usedCredit > 0) {
			        this.pay_yue_credit = true;
			      } else if (usedBalance > 0) {
			        this.pay_yue_full = true;
			      } else if (usedCredit > 0) {
			        this.pay_surplus = true;
			      }
			    } else {
			      if (usedBalance > 0 || usedCredit > 0) {
			        this.pay_yue_credit = true;
			      }
			    }

			    return remainingAfterCredit;
			  },

			  resetPaymentStatus(originalPrice) {
			    let safePrice = this.moneyPrecision(parseFloat(originalPrice) || 0);
			    
// 【关键修复】如果originalPrice是0或无效，使用与 applyBalancePaymentState 一致的公式：应付款（含折扣/红包/积分）- 储值卡
			    if (safePrice === 0 || safePrice < 0.01) {
					const latestTotal = this.checkoutInfo && this.checkoutInfo.total ? this.checkoutInfo.total : this.total;
					const goodsPrice = latestTotal && latestTotal.goods_price ? Number(latestTotal.goods_price) : 0;
					const shippingFee = this.shippingFee ? Number(this.shippingFee) : 0;
					const couponsMoney = Number(this.couponsObject && this.couponsObject.couponsMoney ? this.couponsObject.couponsMoney : 0);
					const discount = Number(latestTotal && latestTotal.discount) || 0;
					const bonusMoney = Number(latestTotal && latestTotal.bonus_money) || Number(this.bonusObject && this.bonusObject.bonusMoney) || 0;
					const integralMoney = Number(latestTotal && latestTotal.integral_money) || 0;
					const totalAmountReset = this.moneyPrecision(Math.max(0, goodsPrice + shippingFee - couponsMoney - discount - bonusMoney - integralMoney));
					const valueCardMoneyReset = this.getValueCardMoney();
					const calculatedPrice = this.moneyPrecision(Math.max(0, totalAmountReset - valueCardMoneyReset));
					if (calculatedPrice > 0) {
						safePrice = calculatedPrice;
					}
			    }
			    
			    this.pay_yue_full = false;
			    this.pay_yue_credit = false;
			    this.pay_surplus = false;
			    this.pay_no = false;

			    this.payment_info = {
			      original_price: safePrice,
			      used_balance: 0,
			      used_credit: 0,
			      remaining_debt: safePrice,
			      adjusted_price: safePrice
			    };
			  },
