			async valueCardLoad(skipEnsurePaymentPriority = false) {
				if (this.valueCardLoading) {
					return;
				}
				this.valueCardLoadCallCount += 1;

				const now = Date.now();
				const checkoutReady =
					this.checkoutInfo &&
					this.checkoutInfo.total &&
					Array.isArray(this.checkoutInfo.total.rec_list) &&
					this.checkoutInfo.total.rec_list.length > 0;
				if (!checkoutReady) {
					if (this.checkoutInfoLoadedAt) {
						this.scheduleValueCardLoadRetry('checkout info not ready');
					}
					return;
				}

				this.resetValueCardLoadRetry();
				this.valueCardLoading = true;

				let i = this.currTab;

				if (this.cartList.length == 0) this.cartList = this.tabs.map(() => []);
				if (this.cartPaginated.length == 0) this.cartPaginated = this.tabs.map(() => 1);
				if (this.cartScrollTop.length == 0) this.cartScrollTop = this.tabs.map(() => 0);

				let page = this.cartList[i].length / this.size;

				page = Math.ceil(page) + 1

				try {
					const requestPayload = {
						page: page,
						size: this.size,
						rec_id: this.checkoutInfo.total.rec_list.join(),
						use_type: i == 0 ? 1 : 0
					};
					const {
						data
					} = await this.$store.dispatch('getValueCard', {
						...requestPayload
					});

					const {
						card_list
					} = data;

					if (!this.checkoutInfoLoadedAt) {
						this.checkoutInfoLoadedAt = Date.now();
					}

					this.valueCartInfo = data;
					const useCardCount = data && typeof data.use_card_count !== 'undefined' ? data.use_card_count : null;
					const notUseCardCount = data && typeof data.not_use_card_count !== 'undefined' ? data.not_use_card_count : null;
					if (card_list) {
						this.$set(this.cartPaginated, i, card_list.length < this.size ? 0 : 1);

						this.$set(this.cartList, i, [...this.cartList[i], ...card_list]);

						this.shopEmpty = this.cartList[i].length == 0;
						this.loadmoreStatus = card_list.length < this.size ? '没有更多了' : '加载中...';
					};

					const selectedCardId = Number(this.valueCardObject && this.valueCardObject.valueCardId ? this.valueCardObject.valueCardId : 0);
					this.applyDefaultValueCard();
					this.autoPriorityApplied = false;
				} catch (error) {
				} finally {
					this.valueCardLoading = false;
					this.resetValueCardLoadRetry();
					if (this.valueCartInfo && this.valueCartInfo.card_list && this.valueCartInfo.card_list.length > 0) {
						this.autoPriorityApplied = false;
					}
					this.valueCardLoaded = true;
					// 【关键修复】打开弹窗时不应该触发自动计算，只有用户点击确定时才重新计算
					// 因此，如果 skipEnsurePaymentPriority 为 true（打开弹窗时），不调用 ensurePaymentPriority
					// 只有在初始化时（skipEnsurePaymentPriority 为 false），才调用 ensurePaymentPriority
					if (!skipEnsurePaymentPriority) {
					this.$nextTick(() => {
						this.ensurePaymentPriority();
					});
					}
				}
			},
