			mergeValueCardData(data = {}, tag = '') {
				// 【关键修复】获取旧的 total 对象，用于保留其他接口返回的字段
				const oldTotal = (this.checkoutInfo && this.checkoutInfo.total) || this.total || {};
				
				// 从接口返回的数据开始合并（后端返回为扁平结构，free_shipping_fee 等在 data 顶层）
				const merged = { ...(data || {}) };
				const responseHasCard = this.hasValidValueCard(merged);

				if (responseHasCard) {
					this.persistValueCardFromResponse(merged, `merge:${tag}`);
					// 【关键修复】即使有储值卡，也要保留旧字段（coupons_money、integral、bonus_money 等）
					// 【核心修复】也需要进行字段过滤，避免用 0 覆盖其他接口设置的有效值
					// 继续执行下面的字段过滤逻辑，不要直接返回
				}

				// 【关键修复】检查接口是否明确返回了 value_card_id: 0（表示用户取消了储值卡）
				// 如果接口返回 value_card_id: 0，说明用户明确取消了储值卡，接口返回的 amount 已经是取消后的正确金额
				// 不应该使用 fallback 逻辑来调整 amount，应该直接使用接口返回的 amount
				const responseValueCardId = Number(merged.value_card_id || 0);
				const responseCardMoney = Number(merged.card_money || 0);
				const isExplicitlyCancelled = responseValueCardId === 0 && responseCardMoney === 0 && merged.amount !== undefined;

				const fallback = this.getPersistedValueCard(tag);
				const totalRef = this.total || {};
				if (fallback) {
					const hadValueCard = this.hasValidValueCard(merged);
					
					// 【关键修复】如果用户明确取消了储值卡，不使用 fallback 的储值卡信息
					if (!isExplicitlyCancelled) {
						merged.value_card_id = fallback.value_card_id;
						merged.card_money = fallback.card_money;
						merged.card_money_formated = fallback.card_money_formated;
						merged.card_formated = merged.card_formated || fallback.card_money_formated;
					} else {
						// 用户明确取消了储值卡，设置为 0
						merged.value_card_id = 0;
						merged.card_money = 0;
						merged.card_money_formated = '0.00';
						merged.card_formated = merged.card_formated || '0.00';
					}
					
					merged.vc_dis = merged.vc_dis || fallback.vc_dis || totalRef.vc_dis;
					merged.vc_dis_money = merged.vc_dis_money || fallback.vc_dis_money || totalRef.vc_dis_money;
					
					// 【关键修复】如果用户明确取消了储值卡，直接使用接口返回的 amount，不再调整
					if (isExplicitlyCancelled) {
						// 接口返回的 amount 已经是取消储值卡后的正确金额，直接使用
						// 不需要再减去 fallback.card_money
					} else if (!hadValueCard && fallback.card_money > 0) {
						// 如果接口没有返回储值卡信息但我们需要补回，需要调整amount
						const currentAmount = this.moneyPrecision(Number(merged.amount) || 0);
						if (currentAmount > 0) {
							// 接口返回的amount可能已经包含了其他扣款（如优惠券），需要再减去储值卡金额
							merged.amount = this.moneyPrecision(Math.max(0, currentAmount - fallback.card_money));
						} else if (fallback.amount_after_card !== null && fallback.amount_after_card !== undefined) {
							merged.amount = fallback.amount_after_card;
						}
					} else if ((merged.amount === undefined || merged.amount === null || isNaN(Number(merged.amount)))) {
						if (fallback.amount_after_card !== null && fallback.amount_after_card !== undefined) {
							merged.amount = fallback.amount_after_card;
						} else if (this.amountPrice !== undefined && this.amountPrice !== null) {
							merged.amount = this.amountPrice;
						}
					}
				}
				
				// 【关键修复】合并旧字段，确保不会丢失其他接口返回的字段（coupons_money、integral、bonus_money 等）
				// 【核心修复】根据接口类型（tag）决定保留哪些字段，避免不同接口互相覆盖
				// - submitValuecard: 只更新储值卡相关字段
				// - submitCoupons: 只更新优惠券相关字段
				// - 其他接口: 更新对应字段
				let filteredMerged = {};
				
				if (tag === 'submitValuecard') {
					// 储值卡接口：只保留储值卡相关字段，不覆盖 coupons_money、integral、bonus_money 等
					const valueCardFields = [
						'value_card_id', 'card_money', 'card_money_formated', 'card_formated',
						'vc_dis', 'vc_dis_money', 'vc_dis_money_formated',
						'amount', 'amount_formated',  // amount 是通用字段，需要更新
						'goods_price', 'goods_price_formated', 'market_price', 'market_price_formated',
						'bonus_goods_price', 'saving', 'saving_formated',
						'dis_amount', 'dis_amount_formated', 'discount', 'discount_formated',
						'goods_number', 'presale_price', 'real_goods_count', 'virtual_goods_count', 'seller_goods_count',
						'need_inv', 'inv_type', 'inv_payee', 'inv_content', 'tax', 'tax_formated',
						'rec_list', 'consignee', 'is_kj', 'free_shipping_fee', 'free_shipping_fee_formated',
						'coupons_count', 'ru_id', 'youhuijia', 'membership_card_buy_money', 'membership_card_buy_money_formated',
						'membership_card_discount_price', 'membership_card_discount_price_formated',
						'success_type', 'ru_shipping_fee_list', 'shopping_fee', 'shopping_fee_formated',
						'order_membership_card_id', 'seller_amount', 'bonus_money', 'bonus_money_formated', 'bonus_id'
					];
					valueCardFields.forEach(field => {
						if (merged.hasOwnProperty(field)) {
							filteredMerged[field] = merged[field];
						}
					});
				} else if (tag === 'submitCoupons') {
					// 优惠券接口：只保留优惠券相关字段，不覆盖 card_money、integral、bonus_money 等
					const couponFields = [
						'coupons_money', 'coupons_money_formated', 'coupons_id', 'coupons_count',
						'amount', 'amount_formated',  // amount 是通用字段，需要更新
						'goods_price', 'goods_price_formated', 'market_price', 'market_price_formated',
						'bonus_goods_price', 'saving', 'saving_formated',
						'dis_amount', 'dis_amount_formated', 'discount', 'discount_formated',
						'goods_number', 'presale_price', 'real_goods_count', 'virtual_goods_count', 'seller_goods_count',
						'need_inv', 'inv_type', 'inv_payee', 'inv_content', 'tax', 'tax_formated',
						'rec_list', 'consignee', 'is_kj', 'free_shipping_fee', 'free_shipping_fee_formated',
						'ru_id', 'youhuijia', 'membership_card_buy_money', 'membership_card_buy_money_formated',
						'membership_card_discount_price', 'membership_card_discount_price_formated',
						'success_type', 'ru_shipping_fee_list', 'shopping_fee', 'shopping_fee_formated',
						'order_membership_card_id', 'seller_amount', 'dis_type'
					];
					couponFields.forEach(field => {
						if (merged.hasOwnProperty(field)) {
							filteredMerged[field] = merged[field];
						}
					});
				} else {
					// 其他接口：保留所有字段（保持原有逻辑）
					filteredMerged = merged;
				}
				
				const result = {
					...oldTotal,      // 保留所有旧字段（包括 coupons_money、integral、bonus_money、surplus 等）
					...filteredMerged // 只覆盖当前接口应该更新的字段
				};
				return result;
			},
			hasValidValueCard(source) {
				if (!source) return false;
				const id = Number(source.value_card_id) || 0;
				const money = Number(source.card_money) || 0;
				return id > 0 && money > 0;
			},
			getPersistedValueCard(tag = '') {
				const candidates = [
					this.lastPersistedValueCard,
					this.total,
					this.valueCardObject ? {
						value_card_id: this.valueCardObject.valueCardId,
						card_money: this.valueCardObject.valueCardMoney,
						card_money_formated: this.valueCardObject.valueCardContent,
						vc_dis: this.valueCardObject.vc_dis,
						vc_dis_money: this.valueCardObject.vc_dis_money,
						amount: this.amountPrice
					} : null
				];

				for (const candidate of candidates) {
					if (candidate && this.hasValidValueCard(candidate)) {
						const formatted = candidate.card_money_formated ||
							candidate.card_formated ||
							`${this.currency}${this.formatCurrencyValue(candidate.card_money)}`;
						const amountAfter = candidate.amount_after_card !== undefined
							? candidate.amount_after_card
							: (candidate.amount !== undefined ? candidate.amount : null);
						return {
							value_card_id: Number(candidate.value_card_id),
							card_money: Number(candidate.card_money),
							card_money_formated: formatted,
							amount_after_card: amountAfter !== null ? Number(amountAfter) : null,
							vc_dis: candidate.vc_dis,
							vc_dis_money: candidate.vc_dis_money
						};
					}
				}
				return null;
			},
			persistValueCardFromResponse(data = {}, tag = '') {
				if (!this.hasValidValueCard(data)) {
					return false;
				}
				const cardMoney = data.card_money != null && data.card_money !== '' ? this.moneyPrecision(Number(data.card_money) || 0) : this.getValueCardMoney();
				this.lastPersistedValueCard = {
					value_card_id: Number(data.value_card_id) || 0,
					card_money: cardMoney,
					card_money_formated: cardMoney > 0 ? 
						(data.card_money_formated || data.card_formated || `${this.currency}${this.formatCurrencyValue(cardMoney)}`) : 
						(data.card_money_formated || data.card_formated || ''),
					amount_after_card: data.amount !== undefined ? Number(data.amount) : null,
					vc_dis: data.vc_dis,
					vc_dis_money: data.vc_dis_money
				};
				return true;
			},
			clearPersistedValueCard(tag = '') {
				this.lastPersistedValueCard = {
					value_card_id: 0,
					card_money: 0,
					card_money_formated: '',
					amount_after_card: null,
					vc_dis: 1,
					vc_dis_money: 0
				};
			},
			seedPersistedValueCardFromTotal(tag = '') {
				if (this.checkoutInfo && this.checkoutInfo.total) {
					this.persistValueCardFromResponse(this.checkoutInfo.total, tag);
				}
			},
		//默认加载
		checkoutDefault() {
			var that = this
			let checkoutPromise = null;
			// 生成版本号
			const version = incrementVersion();
			
			// 【关键修复】标记 order info 接口的 loading 状态
			// 只有 order info 接口返回成功或失败后才能关闭这个 loading
			this.checkoutLoadingClosed = false; // 重置标志，表示 order info loading 还未关闭
			this.orderInfoLoadingActive = true; // 标记 order info loading 正在显示
			this.currentCheckoutPromise = null; // 重置 Promise
			uni.showLoading({
				title: this.$t('lang.loading')
			});
			
		// 根据 is_all_check 决定 cat_rec_id 的值
		// 全选时 cat_rec_id 传空，非全选时传递实际的商品ID列表
		// 【修复】优先使用 reckon_cartgoods 的结果（URL 或 storage），作为唯一可信来源；checkoutInfo.total.rec_list 仅作兜底
		const fromBackendRecList = this.checkoutInfo && this.checkoutInfo.total && Array.isArray(this.checkoutInfo.total.rec_list) && this.checkoutInfo.total.rec_list.length > 0
			? this.checkoutInfo.total.rec_list.join(',')
			: '';
		const fromUrlOrStorage = this.cat_rec_id_from_url || (() => {
			const raw = uni.getStorageSync('cat_rec_id');
			if (raw == null || raw === '') return '';
			// 购物车写入的是 [[rec_id1],[rec_id2],...]，后端需要逗号分隔字符串，统一转成字符串
			if (Array.isArray(raw)) {
				const flat = raw.flatMap(item => Array.isArray(item) ? item : [item]);
				return flat.filter(Boolean).join(',');
			}
			if (typeof raw === 'string') return raw;
			return String(raw);
		})();
		const catRecIdValue = this.is_all_check == 1 ? '' : (fromUrlOrStorage || fromBackendRecList || 0);
		
		// 准备店铺ID参数
		const ruIdValue = this.ru_ids || 0;
			if (uni.getStorageSync('isyong') == 1) {
			if (this.store_id > 0) {
			
				checkoutPromise = this.$store.dispatch('setShoppingCheckout', {
					rec_type: this.rec_type,
					store_id: this.store_id,
					app_version: version,
					leader_id: uni.getStorageSync('leader_id') ? uni.getStorageSync('leader_id') : 0,
					cat_rec_id: catRecIdValue,
					is_all_check: this.is_all_check,
					ru_id: ruIdValue
				})
			} else {
				
				checkoutPromise = this.$store.dispatch('setShoppingCheckout', {
					rec_type: this.rec_type,
					type_id: this.type_id,
					team_id: this.team_id,
					app_version: version,
					leader_id: uni.getStorageSync('leader_id') ? uni.getStorageSync('leader_id') : 0,
					cat_rec_id: catRecIdValue,
					is_all_check: this.is_all_check,
					ru_id: ruIdValue
				})
			}
			} else {
				if (this.store_id > 0) {
				checkoutPromise = this.$store.dispatch('setShoppingCheckout', {
						rec_type: this.rec_type,
						store_id: this.store_id,
						app_version: version,
						leader_id: uni.getStorageSync('leader_id') ? uni.getStorageSync('leader_id') : 0,
						cat_rec_id: catRecIdValue,
						is_all_check: this.is_all_check,
						ru_id: ruIdValue
					})
				} else {
				checkoutPromise = this.$store.dispatch('setShoppingCheckout', {
						rec_type: this.rec_type,
						type_id: this.type_id,
						team_id: this.team_id,
						app_version: version,
						leader_id: uni.getStorageSync('leader_id') ? uni.getStorageSync('leader_id') : 0,
						cat_rec_id: catRecIdValue,
						is_all_check: this.is_all_check,
						ru_id: ruIdValue
					})
				}
			}
			// 确保 loading 只在 order info 接口真正返回数据或失败时才关闭
			// 如果 checkoutPromise 为 null，说明没有调用接口，不应该关闭 loading
			if (checkoutPromise) {
				// 保存 Promise，供其他方法等待完成
				this.currentCheckoutPromise = Promise.resolve(checkoutPromise);
				// 确保 checkoutPromise 是 Promise
				const promise = Promise.resolve(checkoutPromise);
				promise.then((result) => {
					// 请求成功，接口真正返回数据后关闭 loading
					if (!this.checkoutLoadingClosed && this.orderInfoLoadingActive) {
						this.checkoutLoadingClosed = true;
						this.orderInfoLoadingActive = false;
						uni.hideLoading();
					}
					
					// 【关键修复】检查商品列表（rec_list）是否变化，如果变化则清空优惠券状态
					// 确保更换商品后，不会使用旧的优惠券ID
					if (this.checkoutInfo && this.checkoutInfo.total && this.checkoutInfo.total.rec_list) {
						const currentRecList = this.checkoutInfo.total.rec_list;
						const currentRecListStr = JSON.stringify(currentRecList.sort());
						const lastRecListStr = this.lastRecList ? JSON.stringify(this.lastRecList.sort()) : null;
						
						// 如果 rec_list 变化了，清空优惠券相关状态
						if (lastRecListStr !== null && currentRecListStr !== lastRecListStr) {
							this.couponsObject.couponsIdArr = [];
							this.couponsObject.couponsMoney = 0;
							this.couponsObject.couponsContent = this.$t('lang.no_use_coupons');
							// 【关键修复】清空 couponsId 数组，shopCouponList watch 会在需要时重新初始化
							this.couponsObject.couponsId = [];
							this.defaultSelectedCoupon.ids = [];
							this.defaultSelectedCoupon.money = 0;
						}
						
						// 【关键修复】检查 orderinfo 返回的 total.coupons_id
						// 如果 total.coupons_id 存在且不为空，说明后端已自动应用优惠券，需要同步到前端
						// 如果 total.coupons_id 为空或为 0，则使用 coupons_list 中的数据自动选择优惠券
						const backendCouponsId = this.checkoutInfo.total.coupons_id;
						const hasBackendCoupons = backendCouponsId && 
						                            ((Array.isArray(backendCouponsId) && backendCouponsId.length > 0) || 
						                             (typeof backendCouponsId === 'number' && backendCouponsId > 0));
						
						if (hasBackendCoupons) {
							// 后端已返回优惠券ID，同步后端状态到前端
							const backendCouponsIds = Array.isArray(backendCouponsId) 
								? backendCouponsId.map(id => Number(id))
								: [Number(backendCouponsId)];
							const currentCouponsIds = (this.couponsObject.couponsIdArr || []).map(id => Number(id));
							
							// 检查后端返回的优惠券ID是否与前端当前选中的一致
							const isSameIds = backendCouponsIds.length === currentCouponsIds.length &&
							                  backendCouponsIds.every((id) => currentCouponsIds.includes(id)) &&
							                  currentCouponsIds.every((id) => backendCouponsIds.includes(id));
							
							if (!isSameIds) {
								// 同步后端返回的优惠券ID到前端
								this.couponsObject.couponsIdArr = [...backendCouponsIds];
								
								// 同步优惠券金额
								if (this.checkoutInfo.total.coupons_money > 0) {
									this.couponsObject.couponsMoney = Number(this.checkoutInfo.total.coupons_money) || 0;
									this.couponsObject.couponsContent = this.checkoutInfo.total.coupons_money_formated || this.$t('lang.no_use_coupons');
								} else {
									// 【关键修复】如果 coupons_money = 0，需要检查是否有免邮券
									// 构造一个包含必要字段的对象，用于 updateCouponsContent 函数
									const normalizedData = {
										coupons_money: this.checkoutInfo.total.coupons_money || 0,
										free_shipping_fee: this.checkoutInfo.total.free_shipping_fee || 0,
										coupons_id: backendCouponsIds
									};
									this.updateCouponsContent(normalizedData, backendCouponsIds);
								}
								
								// 更新 defaultSelectedCoupon
								this.defaultSelectedCoupon.ids = [...backendCouponsIds];
								this.defaultSelectedCoupon.money = Number(this.checkoutInfo.total.coupons_money) || 0;
								
								// 同步到 couponsId 数组（根据 shopCouponList 和 couponsList 的结构来匹配）
								// 需要根据优惠券的 ru_id 来匹配店铺
								if (this.shopCouponList && Array.isArray(this.shopCouponList) && this.couponsList && Array.isArray(this.couponsList)) {
									// 创建一个映射：uc_id -> { ru_id, cou_money }
									const couponMap = new Map();
									this.couponsList.forEach(coupon => {
										if (coupon.uc_id && backendCouponsIds.includes(Number(coupon.uc_id))) {
											couponMap.set(Number(coupon.uc_id), {
												ru_id: coupon.ru_id,
												cou_money: coupon.cou_money || ''
											});
										}
									});
									
									// 重新初始化 couponsId 数组
									this.couponsObject.couponsId = [];
									this.shopCouponList.forEach((shop, index) => {
										// 查找该店铺对应的优惠券ID（根据 ru_id 匹配）
										let shopCouponId = '';
										let shopCouponMoney = '';
										
										// 遍历后端返回的优惠券ID，找到属于该店铺的优惠券
										for (const ucId of backendCouponsIds) {
											const couponInfo = couponMap.get(ucId);
											if (couponInfo && couponInfo.ru_id == shop.ru_id) {
												shopCouponId = ucId;
												shopCouponMoney = couponInfo.cou_money;
												break; // 每个店铺只取第一个匹配的优惠券
											}
										}
										
										this.couponsObject.couponsId[index] = {
											uc_id: shopCouponId,
											cou_money: shopCouponMoney
										};
									});
								}
							}
						} else {
							// 后端没有返回优惠券ID（为空或为0），需要从 coupons_list 中自动选择
							// 【关键修复】在 checkoutDefault 完成后执行自动选择，确保使用的是最新的 order info 数据
							// 使用 $nextTick 确保 shopCouponList 计算属性已更新
							this.$nextTick(() => {
								// 检查是否已经有选中的优惠券，避免重复选择
								const hasSelectedCoupons = this.couponsObject.couponsIdArr && this.couponsObject.couponsIdArr.length > 0;
								
								if (!hasSelectedCoupons) {
