									let couponListToUse = [];
									
									if (this.shopCouponList && Array.isArray(this.shopCouponList) && this.shopCouponList.length > 0) {
										// 使用 shopCouponList（已经按店铺分组）
										couponListToUse = this.shopCouponList;
									} else if (this.couponsList && Array.isArray(this.couponsList) && this.couponsList.length > 0) {
										// shopCouponList 为空，但 coupons_list 有数据，手动按店铺分组
										
										let dataArr = [];
										this.couponsList.forEach((mapItem) => {
											if (dataArr.length == 0) {
												dataArr.push({
													ru_id: mapItem.ru_id,
													list: [mapItem]
												});
											} else {
												let res = dataArr.some((item) => {
													// 判断相同的店铺，有就添加到当前项
													if (item.ru_id == mapItem.ru_id) {
														item.list.push(mapItem);
														return true;
													}
												});
												if (!res) {
													// 如果没找相同的店铺，添加一个新对象
													dataArr.push({
														ru_id: mapItem.ru_id,
														list: [mapItem]
													});
												}
											}
										});
										couponListToUse = dataArr;
									}
									
									// 如果有可用的优惠券列表，执行自动选择
									if (couponListToUse.length > 0) {
										// 【关键修复】确保 couponsId 数组长度与店铺数量一致
										// 如果 couponsId 数组长度不够，需要先初始化
										if (!this.couponsObject.couponsId || this.couponsObject.couponsId.length < couponListToUse.length) {
											this.couponsObject.couponsId = [];
											couponListToUse.forEach(() => {
												this.couponsObject.couponsId.push({
													uc_id: '',
													cou_money: ''
												});
											});
										}
										
										couponListToUse.forEach((shop, index) => {
											if (shop.list && shop.list.length > 0) {
												// 精准计算最大面额优惠券
												let maxCoupon = shop.list.reduce((max, current) => {
													const currentMoney = parseFloat(current.cou_money) || 0;
													const maxMoney = parseFloat(max.cou_money) || 0;
													return currentMoney > maxMoney ? current : max;
												}, shop.list[0]); // 明确指定初始值
												
												// 执行优惠券选中操作
												if (maxCoupon) {
													this.couponValClick(
														maxCoupon.uc_id,
														maxCoupon.cou_money,
														index
													);
												}
											}
										});
										
										// 异步提交提升稳定性，确保优惠券选中后再调用 submitCoupons 更新总金额
										setTimeout(() => {
											// 【关键修复】标记这是初始化时自动选择优惠券
											this.isInitializingCoupons = true;
