						// 更新 lastRecList
						this.lastRecList = [...currentRecList];
						// 【修复】用后端返回的 rec_list 覆盖并持久化，刷新后再次请求 orderinfo 时仍传这批 rec_id，避免传成默认 10 条
						const recListStr = currentRecList.join(',');
						this.cat_rec_id_from_url = recListStr;
						uni.setStorageSync('cat_rec_id', recListStr);
					}
					
					// 【核心修复】在 checkoutDefault 完成后，按顺序执行初始化接口
					// 顺序：优惠券 → 储值卡 → 余额先用后付 → 积分 → 红包
					this.$nextTick(() => {
						this.executeInitializationAPIsInOrder().then(() => {
							// 【关键修复】如果没有余额/信用付，executeInitializationAPIsInOrder 中的 surplusvValHandlePromise
							// 会直接返回（因为 surplusAmount === 0），不会调用接口获取包含运费的金额
							// 所以需要在这里手动调用一次，确保金额包含运费
							if (!this.balancePaymentActive && this.use_surplus_val === 0 && this.use_credit_val === 0) {
								// 没有余额/信用付，需要调用接口获取包含运费的金额
								this.surplusvValHandle();
							}
						}).catch((error) => {
							// 静默处理错误，避免影响主流程
							console.error('[executeInitializationAPIsInOrder] 执行失败:', error);
						});
					});
					
					// 清除 Promise 引用
					this.currentCheckoutPromise = null;
				}).catch((error) => {
					// 请求失败，接口失败后关闭 loading
					if (!this.checkoutLoadingClosed && this.orderInfoLoadingActive) {
						this.checkoutLoadingClosed = true;
						this.orderInfoLoadingActive = false;
						uni.hideLoading();
					}
					// 清除 Promise 引用
					this.currentCheckoutPromise = null;
					
					// 双重判断：如果 status === 'failed' 且 errors.code === 6652，清除 cat_rec_id 缓存
					// 数据结构: {"status":"failed","errors":{"code":6652,"message":"提交失败，请重试"}}
					if (error && error.status === 'failed' && error.errors && error.errors.code === 6652) {
						// 异常情况：清除缓存中的 cat_rec_id 值
						uni.removeStorageSync('cat_rec_id');
					}
					// 如果 status === 'failed' 但 errors.code 不是 6652，则不清除 cat_rec_id
					
					// 获取错误信息，使用 errors.message
					let errorMessage = '提交失败，请重试';
					if (error && error.errors && error.errors.message) {
						errorMessage = error.errors.message;
					}
					
					// 使用自定义 toast 显示错误信息
					if (this.$refs && this.$refs.customToast) {
						this.$refs.customToast.showToast({
							title: errorMessage,
							icon: 'none',
							duration: 2000
						});
						
						// 延迟返回上一级，确保 toast 显示
						setTimeout(() => {
							uni.navigateBack({
								delta: 1
							});
						}, 500);
					} else {
						// 如果自定义 toast 不可用，使用默认 toast
						uni.showToast({
							title: errorMessage,
							icon: 'none',
							duration: 2000
						});
						setTimeout(() => {
							uni.navigateBack({
								delta: 1
							});
						}, 500);
					}
				}); }
			},
			// 【核心修复】按顺序执行初始化接口，避免数据覆盖问题
			// 顺序：优惠券 → 储值卡 → 余额先用后付 → 积分 → 红包
			// 每个接口等待上一个接口完成并更新状态后，再执行下一个
			// 如果某个接口返回 error（status === 'failed'），阻断后续执行
			async executeInitializationAPIsInOrder() {
				try {
					// 1. 优惠券接口
					if (this.couponsObject && this.couponsObject.couponsIdArr && this.couponsObject.couponsIdArr.length > 0) {
						const couponResult = await this.submitCouponsPromise();
						if (couponResult && couponResult.status === 'failed') {
							return;
						}
					}

					// 2. 储值卡接口
					if (this.valueCardObject && this.valueCardObject.valueCardId && this.valueCardObject.valueCardId > 0) {
						const valueCardResult = await this.submitValuecardPromise();
						if (valueCardResult && valueCardResult.status === 'failed') {
							return;
						}
					}
					
					// 3. 余额先用后付接口
					if (this.balancePaymentActive || (this.use_surplus_val > 0 || this.use_credit_val > 0)) {
						const surplusResult = await this.surplusvValHandlePromise();
						if (surplusResult && surplusResult.status === 'failed') {
							return;
						}
					}
					
					// 4. 积分接口
					if (this.use_integral_val && this.use_integral_val > 0) {
						const integralResult = await this.integralSelfHandlePromise();
						if (integralResult && integralResult.status === 'failed') {
							return;
						}
					}
					
					// 5. 红包接口
					if (this.bonusObject && this.bonusObject.bonusId && this.bonusObject.bonusId > 0) {
						const bonusResult = await this.submitBonusPromise();
						if (bonusResult && bonusResult.status === 'failed') {
							return;
						}
					}
				} catch (error) {
					console.error('[executeInitializationAPIsInOrder] 执行过程中出错:', error);
				}
			},
			//选择收货地址
			checkoutAddress() {
				if (this.checkoutInfo.consignee.nearbyleader > 0) {
					const lngAndLat = {
						lng: this.checkoutInfo.consignee.lng,
						lat: this.checkoutInfo.consignee.lat
					}
					uni.setStorageSync('addressLngLat', JSON.stringify(lngAndLat));
				}
				const nearbyleader = this.checkoutInfo.consignee.nearbyleader || 0;
				uni.navigateTo({
					url: '/pagesB/address/address?type=checkout&nearbyleader=' + nearbyleader
				})
			},
			//发票展开
			invoiceSelect() {
				if (this.checkoutInfo.cross_border) {
					return false
				}

				this.showBase = true
				uni.request({
					url: this.websiteUrl + '/api/invoice',
					method: 'GET',
					header: {
						'Content-Type': 'application/json',
						'token': uni.getStorageSync('token'),
						'X-Client-Hash': uni.getStorageSync('client_hash')
					},
					success: (res) => {
						let data = res.data.data;
						this.invoice.invoiceCompany = data.order_invoice_info;
						this.invoice.user_vat_invoice = data.user_vat_invoice;

						//是否显示增值税发票按钮
						this.invoice.increment = this.invoice.user_vat_invoice ? true : false;
