						} else if (this.invoice.company_tid == '') {
							uni.showToast({
								title: this.$t('lang.fill_in_taxpayer_id_number'),
								icon: 'none'
							})
							return false
						} else if (this.invoice.inv_email == '') {
							uni.showToast({
								title: '请填写邮箱',
								icon: 'none'
							})
							return false
						} else if (this.invoice.inv_mobile == '') {
							uni.showToast({
								title: '请填写手机号码',
								icon: 'none'
							})
							return false
						} else {
							this.showBase = false
						}
					} else {
						// 电子发票 -个人
						if (this.invoice.inv_email == '') {
							uni.showToast({
								title: '请填写邮箱',
								icon: 'none'
							})
							return false
						} else if (this.invoice.inv_mobile == '') {
							uni.showToast({
								title: '请填写手机号码',
								icon: 'none'
							})
							return false
						} else {
							this.showBase = false
						}
					}
				} else {
					if (this.invoice.company) {
						if (this.invoice.company_name == '') {
							uni.showToast({
								title: this.$t('lang.fill_in_company_name'),
								icon: 'none'
							});
							return false
						} else if (this.invoice.company_tid == '') {
							uni.showToast({
								title: this.$t('lang.fill_in_taxpayer_id_number'),
								icon: 'none'
							});
							return false
						} else {
							this.showBase = false
						}
					} else {
						// 普通发票 - 个人
						this.showBase = false
					}
				}

				this.getChangetax();
			},
			getChangetax() {
				uni.request({
					url: this.websiteUrl + '/api/trade/changetax',
					method: 'POST',
					data: {
						total: this.total,
						inv_content: this.invoice.invoiceConent
					},
					header: {
						'Content-Type': 'application/json',
						'token': uni.getStorageSync('token'),
						'X-Client-Hash': uni.getStorageSync('client_hash')
					},
					success: ({
						data: {
							data
						}
					}) => {
						const normalized = this.mergeValueCardData(data, 'getChangetax');
						this.$store.dispatch('setCheckoutTotal', normalized)
						this.amountPrice = normalized.amount
						this.ratePrice = normalized.rate_price
						this.getType = false
						// 储值卡扣款以后端返回的 card_money 为准
					if (normalized.value_card_id > 0 && !this.userValueCardCancelled) {
						const cardMoney = this.moneyPrecision(Number(normalized.card_money) || 0);
						this.valueCardObject.valueCardMoney = cardMoney;
						if (cardMoney > 0) {
							this.valueCardObject.valueCardContent = normalized.card_money_formated || (this.currency + this.formatCurrencyValue(cardMoney));
							this.userValueCardCancelled = false;
						} else {
							this.valueCardObject.valueCardContent = this.$t('lang.no_use_value_card');
						}
						this.valueCardObject.valueCardId = normalized.value_card_id;
					} else {
						if (this.userValueCardCancelled) {
							this.valueCardObject.valueCardId = 0;
						}
						this.valueCardObject.valueCardMoney = 0;
						this.valueCardObject.valueCardContent = this.$t('lang.no_use_value_card');
					}
					this.persistValueCardFromResponse(normalized, 'getChangetax');

						// 【关键修复】使用统一的辅助函数处理优惠券显示逻辑
						this.updateCouponsContent(normalized)

						if (normalized.bonus_money > 0) {
							this.bonusObject.bonusContent = normalized.bonus_money_formated
						} else {
							this.bonusObject.bonusContent = this.$t('lang.no_use_bonus')
						}

						this.total.integral_money = normalized.integral_money
						this.ensurePaymentPriority();

						if (!this.balancePaymentActive) {
							this.use_surplus_val = 0
							this.use_credit_val = 0
						}
					}
				})
			},
			//红包选择
			bonusActive(id) {
				if (this.bonusObject.bonusId != id) {
					this.bonusObject.bonusId = id
				} else {
					this.bonusObject.bonusId = 0
				}
			},
			//红包确认
			submitBonus() {
				// 【关键修复】直接使用 checkoutInfo.total 而不是 this.total，确保获取最新的值（包括 coupons_money、integral 等）
				const latestTotal = this.checkoutInfo && this.checkoutInfo.total ? this.checkoutInfo.total : this.total;
				uni.request({
					url: this.websiteUrl + '/api/trade/changebon',
					method: 'POST',
					data: {
						bonus_id: this.bonusObject.bonusId,
						total: latestTotal,
						shipping_id: this.shipping_id,
						// 【关键修复】如果有优惠券并且使用的情况，传递已选中的优惠券ID
						uc_id: (this.couponsObject.couponsIdArr && this.couponsObject.couponsIdArr.length > 0) ? this.couponsObject.couponsIdArr : []
					},
					header: {
						'Content-Type': 'application/json',
						'token': uni.getStorageSync('token'),
						'X-Client-Hash': uni.getStorageSync('client_hash')
					},
					success: ({
						data: {
							data
						}
					}) => {
						const normalized = this.mergeValueCardData(data, 'submitBonus');
						this.$store.dispatch('setCheckoutTotal', normalized)
						if (normalized.bonus_money > 0) {
							this.bonusObject.bonusContent = normalized.bonus_money_formated
						} else {
							this.bonusObject.bonusContent = this.$t('lang.no_use_bonus')
						}
						this.total.bonus_money = normalized.bonus_money
						this.amountPrice = normalized.amount
						this.bonusObject.bonusMoney = normalized.bonus_money
					// 储值卡扣款以后端返回的 card_money 为准
					if (normalized.value_card_id > 0 && !this.userValueCardCancelled) {
						const cardMoney = this.moneyPrecision(Number(normalized.card_money) || 0);
						this.valueCardObject.valueCardMoney = cardMoney;
						if (cardMoney > 0) {
							this.valueCardObject.valueCardContent = normalized.card_money_formated || (this.currency + this.formatCurrencyValue(cardMoney));
							this.userValueCardCancelled = false;
						} else {
							this.valueCardObject.valueCardContent = this.$t('lang.no_use_value_card');
						}
						this.valueCardObject.vc_dis_money = normalized.vc_dis_money || this.valueCardObject.vc_dis_money;
						this.valueCardObject.vc_dis = normalized.vc_dis || this.valueCardObject.vc_dis;
						this.valueCardObject.valueCardId = normalized.value_card_id;
					} else {
						if (this.userValueCardCancelled) {
							this.valueCardObject.valueCardId = 0;
						}
						this.valueCardObject.valueCardMoney = 0;
						this.valueCardObject.valueCardContent = this.$t('lang.no_use_value_card');
					}
					this.persistValueCardFromResponse(normalized, 'submitBonus');
						this.ensurePaymentPriority();
						// 【与储值卡一致】红包切换/取消后，若余额/先用后付已开启，重新计算 先用后付 金额
						if (this.balancePaymentActive) {
							this.surplusvValHandle();
						}
					},
					fail: () => {
						// 【关键修复】只有在 order info loading 已关闭时才关闭 loading
						// 如果 order info loading 还在显示，不关闭它（让它继续显示）
						if (this.checkoutLoadingClosed || !this.orderInfoLoadingActive) {
							uni.hideLoading();
						}
					},
					complete: () => {
						// 【关键修复】只有在 order info loading 已关闭时才关闭 loading
						// 如果 order info loading 还在显示，不关闭它（让它继续显示）
						if (this.checkoutLoadingClosed || !this.orderInfoLoadingActive) {
							uni.hideLoading();
						}
					}
				})
				this.bonusObject.bonusBase = false
				this.surplus_status = false
			},
			//优惠券选择
			couponsActive(id) {
				if (this.couponsObject.couponsId != id) {
					this.couponsObject.couponsId = id
				} else {
					this.couponsObject.couponsId = 0
				}
			},
			updateCouponsContent(normalized, backendCouponsIds = null) {
				// 1. 优先检查是否有金额优惠券
				if (normalized.coupons_money > 0) {
					this.couponsObject.couponsContent = normalized.coupons_money_formated
					return;
				}
				
				// 2. 检查是否有免邮费用（商品有邮费时，免邮券会返回免邮费用）
				if (normalized.free_shipping_fee > 0) {
					this.couponsObject.couponsContent = '免邮券';
					return;
				}
				
				// 3. 如果 free_shipping_fee = 0，需要检查是否选中了免邮券（商品全部包邮的情况）
				// 检查接口返回的 coupons_id 数组，如果有值说明优惠券已应用
				const couponsIdsFromBackend = backendCouponsIds !== null ? backendCouponsIds : (normalized.coupons_id || []);
				const hasBackendCoupons = Array.isArray(couponsIdsFromBackend) && couponsIdsFromBackend.length > 0;
				
				// 检查前端选中的优惠券ID数组
				const frontendCouponsIds = this.couponsObject.couponsIdArr || [];
				const hasFrontendCoupons = Array.isArray(frontendCouponsIds) && frontendCouponsIds.length > 0;
				
				// 如果接口返回了优惠券ID或前端选中了优惠券，需要进一步判断是否包含免邮券
				if (hasBackendCoupons || hasFrontendCoupons) {
					// 获取要检查的优惠券ID数组（优先使用接口返回的，否则使用前端选中的）
					const couponsIdsToCheck = hasBackendCoupons ? couponsIdsFromBackend.map(id => Number(id)) : frontendCouponsIds.map(id => Number(id));
					
					// 检查 couponsList 中是否有免邮券（cou_type = 5）
					let hasFreeShippingCoupon = false;
					if (this.couponsList && Array.isArray(this.couponsList) && this.couponsList.length > 0) {
						hasFreeShippingCoupon = this.couponsList.some(coupon => {
							const ucId = Number(coupon.uc_id);
							const couType = Number(coupon.cou_type || 0);
							// 检查是否在选中的优惠券ID中，且是免邮券类型（cou_type = 5）
							return couponsIdsToCheck.includes(ucId) && couType === 5;
						});
					}
					
					// 如果选中了免邮券，即使 free_shipping_fee = 0（商品全部包邮），也显示"免邮券"
					if (hasFreeShippingCoupon) {
						this.couponsObject.couponsContent = '免邮券';
					} else {
						// 如果选中了其他类型的优惠券，但金额为0，显示"未选择优惠券"
						this.couponsObject.couponsContent = this.$t('lang.no_use_coupons')
					}
				} else {
					// 没有选中任何优惠券
					this.couponsObject.couponsContent = this.$t('lang.no_use_coupons')
				}
			},
			//优惠券确定
			submitCoupons(uc_id) {
				// 【关键修复】确保 checkoutDefault 已完成，使用最新的 total 和 shipping_id
				// 如果 checkoutDefault 还在进行中，等待它完成后再调用优惠券接口
				const waitForCheckoutDefault = () => {
					if (this.currentCheckoutPromise && this.orderInfoLoadingActive && !this.checkoutLoadingClosed) {
						return this.currentCheckoutPromise.then(() => {
							// 等待一个微任务，确保 checkoutInfo 和 shipping_id 已更新
							return new Promise(resolve => {
								this.$nextTick(() => {
									setTimeout(resolve, 100);
								});
							});
						}).catch((error) => {
							return Promise.resolve();
						});
					}
					return Promise.resolve();
				};
				
					// 执行等待逻辑，然后调用接口
				waitForCheckoutDefault().then(() => {
					// 确保使用最新的 total 和 shipping_id
					const latestTotal = this.checkoutInfo && this.checkoutInfo.total ? this.checkoutInfo.total : this.total;
					const latestShippingId = this.shipping_id && this.shipping_id.length > 0 ? this.shipping_id : [];
					
					// 【关键修复】在使用余额 / 信用付时，确保将最新的余额金额同步到 total.surplus / total.surplus_formated
					// 后端 /api/trade/changecou 会直接使用 total.surplus 计算金额，如果这里始终是 0，就会导致后端忽略余额
					let totalForRequest = { ...latestTotal };
					try {
						// 1. 计算当前实际使用的余额金额（优先使用 balance_money，其次 payment_info.used_balance）
						const actualBalanceAmount = this.balance_money > 0
							? Number(this.balance_money)
							: (this.payment_info && Number(this.payment_info.used_balance) > 0
								? Number(this.payment_info.used_balance)
								: 0);
						
						// 2. 只有在余额开关开启且实际金额 > 0 时，才覆盖 total.surplus；否则保持后端原值（通常为 0）
						if (this.balancePaymentActive && actualBalanceAmount > 0) {
							const preciseBalance = this.moneyPrecision
								? this.moneyPrecision(actualBalanceAmount)
								: Number(actualBalanceAmount.toFixed(2));
							
							totalForRequest.surplus = preciseBalance;
							
							// 如果后端已经给了格式化字段，就尽量复用；否则本地格式化一个，避免传空字符串
							if (!totalForRequest.surplus_formated || Number(totalForRequest.surplus_formated) === 0) {
								const currencySymbol = this.currency || '¥';
								const formatFn = this.formatCurrencyValue || (v => Number(v).toFixed(2));
								totalForRequest.surplus_formated = `${currencySymbol}${formatFn(preciseBalance)}`;
							}
						}
					} catch (e) {
						totalForRequest = { ...latestTotal };
					}
					
					// 【关键修复】获取当前要提交的优惠券ID数组
					// 必须基于当前弹窗中实际选中的优惠券（couponsId），而不是使用可能过期的 couponsIdArr
					let currentCouponIds = []
					if (uc_id) {
						// 如果传入了 uc_id 参数，直接使用
						currentCouponIds = [uc_id]
					} else {
						// 如果没有传入 uc_id，从 couponsId 中重新计算当前选中的优惠券ID
						// 这样可以确保使用的是当前弹窗中实际选中的优惠券，而不是上一次的值
						currentCouponIds = []
						if (this.couponsObject.couponsId && Array.isArray(this.couponsObject.couponsId)) {
							// 【关键修复】只提取有效的 uc_id，并且确保 uc_id 不为空字符串
							this.couponsObject.couponsId.forEach(v => {
								if (v && v.uc_id && v.uc_id !== '' && v.uc_id !== 0) {
									currentCouponIds.push(v.uc_id)
								}
							})
						}
						
						// 【关键修复】额外检查：如果 currentCouponIds 为空，但 couponsIdArr 不为空
						// 说明 couponsId 可能没有正确更新，强制使用空数组，避免使用旧的优惠券ID
						if (currentCouponIds.length === 0 && this.couponsObject.couponsIdArr && this.couponsObject.couponsIdArr.length > 0) {
							currentCouponIds = [];
						}
					}
					
					// 检查是否与当前已应用的优惠券相同（避免重复调用接口）
					// 注意：这里比较的是 total.coupons_id（接口返回的已应用优惠券ID）和 couponsObject.couponsMoney（当前UI状态的优惠券金额）
					// 只有当优惠券ID和金额都完全相同时，才跳过接口调用
					if (this.couponsObject.couponsMoney > 0 && currentCouponIds.length > 0) {
						// 获取当前要提交的优惠券金额
						const currentCouponMoney = this.couponsObject.couponsMoney > 0 ? this.couponsObject.couponsMoney : 0
						
						// 检查优惠券ID是否相同（从接口返回的 coupons_id 字段获取）
						const currentTotalCouponsIds = (latestTotal.coupons_id || []).map(id => Number(id))
						const currentCouponIdsNum = currentCouponIds.map(id => Number(id))
						const isSameIds = currentCouponIdsNum.length === currentTotalCouponsIds.length &&
						                  currentCouponIdsNum.every((id) => currentTotalCouponsIds.includes(id)) &&
						                  currentTotalCouponsIds.every((id) => currentCouponIdsNum.includes(id))
						
						// 检查金额是否相同（允许小数点误差）
						const isSameMoney = Math.abs(Number(currentCouponMoney) - Number(this.defaultSelectedCoupon.money)) < 0.01
						
						if (isSameIds && isSameMoney) {
							// 直接关闭弹窗
							this.couponsObject.couponsBase = false
							return;
						}
					}
					
					// 【关键修复】更新 couponsIdArr 为当前选中的优惠券ID数组
					// 确保 couponsIdArr 与当前弹窗中实际选中的优惠券一致
					this.couponsObject.couponsIdArr = [...currentCouponIds]
					
					// 如果传入了 uc_id 参数，更新 couponsId[0]
					if (uc_id) {
						if (!this.couponsObject.couponsId[0]) {
							this.couponsObject.couponsId[0] = {
								uc_id: '',
								cou_money: ''
							}
						}
						this.couponsObject.couponsId[0].uc_id = uc_id;
						this.couponsObject.couponsId[0].cou_money = '';
					}
					
					// 【关键修复】优惠券接口使用独立的 loading，不影响 order info 的 loading
					// 如果 order info loading 还在显示，不关闭它，直接显示优惠券的 loading（会覆盖）
					// 在 complete 中，如果 order info loading 还在显示，就不关闭 loading
					uni.showLoading({
						title: '价格计算中~~'
					});
					uni.request({
						url: this.websiteUrl + '/api/trade/changecou',
						method: 'POST',
						data: {
							uc_id: currentCouponIds, // 【关键修复】使用重新计算的 currentCouponIds，而不是可能过期的 couponsIdArr
							total: latestTotal,
							shipping_id: latestShippingId
					},
					header: {
						'Content-Type': 'application/json',
						'token': uni.getStorageSync('token'),
						'X-Client-Hash': uni.getStorageSync('client_hash')
					},
					success: ({
						data: {
							data
						}
					}) => {
					const normalized = this.mergeValueCardData(data, 'submitCoupons');
					this.$store.dispatch('setCheckoutTotal', normalized)
					
					// 【关键修复】使用统一的辅助函数处理优惠券显示逻辑
					this.updateCouponsContent(normalized)

					var that = this
					// 使用 $set 确保响应式更新
					if (that.checkoutInfo && that.checkoutInfo.total) {
						// 【关键修复】直接使用后端返回的 coupons_money（可能是字符串 "50.00" 或数字），确保传递给后续接口
						// 后端返回的值直接使用，不做转换，因为后续接口需要这个值
						const couponsMoney = normalized.coupons_money !== undefined && normalized.coupons_money !== null 
							? normalized.coupons_money 
							: 0;
						that.$set(that.checkoutInfo.total, 'coupons_money', couponsMoney);
						
						// 同时更新 coupons_money_formated
						if (normalized.coupons_money_formated) {
							that.$set(that.checkoutInfo.total, 'coupons_money_formated', normalized.coupons_money_formated);
						} else if (couponsMoney > 0) {
							// 如果没有格式化字段，但 coupons_money > 0，生成一个格式化字符串
							const formattedValue = typeof couponsMoney === 'string' ? couponsMoney : Number(couponsMoney).toFixed(2);
							that.$set(that.checkoutInfo.total, 'coupons_money_formated', that.currency + formattedValue);
						} else {
							that.$set(that.checkoutInfo.total, 'coupons_money_formated', '0.00');
						}
						
						// 【关键修复】同时更新 coupons_id，确保后续接口能获取到正确的优惠券ID
						if (normalized.coupons_id !== undefined) {
							that.$set(that.checkoutInfo.total, 'coupons_id', normalized.coupons_id);
						}
						
						// 【修复免邮券显示问题】明确更新 free_shipping_fee 和 free_shipping_fee_formated
						if (normalized.free_shipping_fee !== undefined) {
							that.$set(that.checkoutInfo.total, 'free_shipping_fee', normalized.free_shipping_fee);
						}
						if (normalized.free_shipping_fee_formated) {
							that.$set(that.checkoutInfo.total, 'free_shipping_fee_formated', normalized.free_shipping_fee_formated);
						} else if (normalized.free_shipping_fee > 0) {
							// 如果没有格式化字段，但 free_shipping_fee > 0，生成一个格式化字符串
							const formattedValue = typeof normalized.free_shipping_fee === 'string' 
								? normalized.free_shipping_fee 
								: Number(normalized.free_shipping_fee).toFixed(2);
							that.$set(that.checkoutInfo.total, 'free_shipping_fee_formated', that.currency + formattedValue);
						}
						
						// 【关键修复】完全使用后端返回的 amount，不再使用 goods_price 或其他计算值
						// 后端返回的 normalized.amount 已经包含了所有扣款（优惠券、折扣、储值卡、余额、信用付等）
						// 直接使用接口返回的 amount 更新 total.amount 和 amountPrice
						const finalAmount = normalized.amount ? Number(normalized.amount) : 
						                 (that.checkoutInfo && that.checkoutInfo.total && that.checkoutInfo.total.amount ? Number(that.checkoutInfo.total.amount) : 0);
						that.$set(that.checkoutInfo.total, 'amount', finalAmount);
						// 【关键修复】直接使用后端返回的 amount 更新应付金额
						that.amountPrice = finalAmount;
						// 重置初始化标志（如果存在）
						if (that.isInitializingCoupons) {
							that.isInitializingCoupons = false;
						}
					}
					that.couponsObject.couponsMoney = normalized.coupons_money || 0
						
						// 接口返回后，更新默认选中的优惠券ID和金额（用于下次判断是否相同）
						// 注意：每次接口返回后都要更新，而不是只在初始化时更新
						if (normalized.coupons_money > 0) {
							that.defaultSelectedCoupon.ids = [...(that.couponsObject.couponsIdArr || [])]
							that.defaultSelectedCoupon.money = Number(normalized.coupons_money) || 0
						} else {
							// 取消优惠券时，清空默认选中记录
							that.defaultSelectedCoupon.ids = []
							that.defaultSelectedCoupon.money = 0
						}
					// 储值卡扣款以后端返回的 card_money 为准
					if (normalized.value_card_id > 0 && !that.userValueCardCancelled) {
						const cardMoney = that.moneyPrecision(Number(normalized.card_money) || 0);
						that.valueCardObject.valueCardMoney = cardMoney;
						if (cardMoney > 0) {
							that.valueCardObject.valueCardContent = normalized.card_money_formated || (that.currency + that.formatCurrencyValue(cardMoney));
							that.userValueCardCancelled = false;
						} else {
							that.valueCardObject.valueCardContent = that.$t('lang.no_use_value_card');
						}
						that.valueCardObject.vc_dis_money = normalized.vc_dis_money || that.valueCardObject.vc_dis_money;
						that.valueCardObject.vc_dis = normalized.vc_dis || that.valueCardObject.vc_dis;
						that.valueCardObject.valueCardId = normalized.value_card_id;
					} else {
						if (that.userValueCardCancelled) {
							that.valueCardObject.valueCardId = 0;
						}
						that.valueCardObject.valueCardMoney = 0;
						that.valueCardObject.valueCardContent = that.$t('lang.no_use_value_card');
					}
						this.persistValueCardFromResponse(normalized, 'submitCoupons');
						this.ensurePaymentPriority();
							this.getType = true
					},
					fail: () => {
						// 【关键修复】只有在 order info loading 已关闭时才关闭 loading
						// 如果 order info loading 还在显示，不关闭它（让它继续显示）
						if (this.checkoutLoadingClosed || !this.orderInfoLoadingActive) {
							uni.hideLoading();
						}
					},
					complete: () => {
						// 【关键修复】只有在 order info loading 已关闭时才关闭 loading
						// 如果 order info loading 还在显示，不关闭它（让它继续显示）
						if (this.checkoutLoadingClosed || !this.orderInfoLoadingActive) {
							uni.hideLoading();
						}
					}
				});
				this.couponsObject.couponsBase = false
				this.surplus_status = false
				}); // 关闭 waitForCheckoutDefault().then() 回调
			},
			// 【核心修复】Promise 版本的接口调用方法，用于顺序执行
			// 优惠券接口 Promise 版本
			submitCouponsPromise() {
				return new Promise((resolve, reject) => {
					const latestTotal = this.checkoutInfo && this.checkoutInfo.total ? this.checkoutInfo.total : this.total;
					const latestShippingId = this.shipping_id && this.shipping_id.length > 0 ? this.shipping_id : [];
					const currentCouponIds = this.couponsObject.couponsIdArr || [];
					
					if (currentCouponIds.length === 0) {
						resolve({ status: 'success', skip: true });
						return;
					}
					
					uni.request({
						url: this.websiteUrl + '/api/trade/changecou',
						method: 'POST',
						data: {
							uc_id: currentCouponIds,
							total: latestTotal,
							shipping_id: latestShippingId
						},
						header: {
							'Content-Type': 'application/json',
							'token': uni.getStorageSync('token'),
							'X-Client-Hash': uni.getStorageSync('client_hash')
						},
						success: ({ data: { data, status } }) => {
							if (status === 'failed') {
								reject({ status: 'failed', data });
								return;
							}
							const normalized = this.mergeValueCardData(data, 'submitCoupons');
							this.$store.dispatch('setCheckoutTotal', normalized);
							this.updateCouponsContent(normalized);
							if (this.checkoutInfo && this.checkoutInfo.total) {
								this.$set(this.checkoutInfo.total, 'coupons_money', normalized.coupons_money || 0);
								this.$set(this.checkoutInfo.total, 'coupons_id', normalized.coupons_id);
								this.$set(this.checkoutInfo.total, 'amount', normalized.amount);
							}
							this.amountPrice = normalized.amount;
							this.couponsObject.couponsMoney = normalized.coupons_money || 0;
							this.defaultSelectedCoupon.ids = [...currentCouponIds];
							this.defaultSelectedCoupon.money = Number(normalized.coupons_money) || 0;
							resolve({ status: 'success', data: normalized });
						},
						fail: (error) => {
							reject({ status: 'failed', error });
						}
					});
				});
			},
			// 储值卡接口 Promise 版本
			submitValuecardPromise() {
				return new Promise((resolve, reject) => {
					const latestTotal = this.checkoutInfo && this.checkoutInfo.total ? this.checkoutInfo.total : this.total;
					const vid = this.valueCardObject.valueCardId || 0;
					
					if (vid === 0) {
						resolve({ status: 'success', skip: true });
						return;
					}
					
				uni.request({
					url: this.websiteUrl + '/api/trade/changecard',
					method: 'POST',
					data: {
						vid: vid,
						total: latestTotal,
						shipping_id: this.shipping_id,
						// 【关键修复】如果有优惠券并且使用的情况，传递已选中的优惠券ID
						uc_id: (this.couponsObject.couponsIdArr && this.couponsObject.couponsIdArr.length > 0) ? this.couponsObject.couponsIdArr : []
					},
						header: {
							'Content-Type': 'application/json',
							'token': uni.getStorageSync('token'),
							'X-Client-Hash': uni.getStorageSync('client_hash')
						},
						success: ({ data: { data, status } }) => {
							if (status === 'failed') {
								reject({ status: 'failed', data });
								return;
							}
							const normalized = this.mergeValueCardData(data, 'submitValuecard');
							this.$store.dispatch('setCheckoutTotal', normalized);
							this.amountPrice = normalized.amount;
							if (data.card_money > 0) {
								this.valueCardObject.valueCardContent = data.card_formated;
								this.userValueCardCancelled = false;
							} else {
								this.valueCardObject.valueCardContent = this.$t('lang.no_use_value_card');
							}
							this.valueCardObject.vc_dis = data.vc_dis;
							this.valueCardObject.valueCardId = normalized.value_card_id;
							resolve({ status: 'success', data: normalized });
						},
						fail: (error) => {
							reject({ status: 'failed', error });
						}
					});
				});
			},
			// 余额先用后付接口 Promise 版本（与 surplusvValHandle 同一套计算逻辑，不依赖 surplus_credit_line 已赋值）
			surplusvValHandlePromise() {
				return new Promise((resolve, reject) => {
					let balanceAmount = 0;
					if (this.balancePaymentActive && this.use_surplus_val === 1) {
						if (this.payment_info && this.payment_info.used_balance && Number(this.payment_info.used_balance) > 0) {
							balanceAmount = Number(this.payment_info.used_balance);
						} else if (this.balance_money && Number(this.balance_money) > 0) {
							balanceAmount = Number(this.balance_money);
						}
					}
					let creditAmount = 0;
					if (this.use_credit_val === 1) {
						const latestTotal = this.checkoutInfo && this.checkoutInfo.total ? this.checkoutInfo.total : this.total;
						const goodsPrice = latestTotal && latestTotal.goods_price ? Number(latestTotal.goods_price) : 0;
						const shippingFee = this.shippingFee ? Number(this.shippingFee) : 0;
						const couponsMoney = Number(this.couponsObject && this.couponsObject.couponsMoney ? this.couponsObject.couponsMoney : 0);
						const discount = Number(latestTotal && latestTotal.discount) || 0;
						const bonusMoney = Number(latestTotal && latestTotal.bonus_money) || Number(this.bonusObject && this.bonusObject.bonusMoney) || 0;
						const integralMoney = Number(latestTotal && latestTotal.integral_money) || 0;
						const valueCardMoney = this.getValueCardMoney();
						const amountAfterValueCard = this.moneyPrecision(Math.max(0, goodsPrice + shippingFee - couponsMoney - discount - bonusMoney - integralMoney - valueCardMoney));
						const remainingAfterBalance = this.moneyPrecision(Math.max(0, amountAfterValueCard - balanceAmount));
						const availableCredit = this.moneyPrecision(Math.max(this.surplus_credit_line_available || 0, 0));
						if (remainingAfterBalance > 0 && availableCredit > 0) {
							creditAmount = this.moneyPrecision(Math.min(availableCredit, remainingAfterBalance));
						}
					}
					const surplusAmount = this.moneyPrecision(balanceAmount + creditAmount);
					
					if (surplusAmount === 0) {
						resolve({ status: 'success', skip: true });
						return;
					}
					
				const latestTotal = this.checkoutInfo && this.checkoutInfo.total ? this.checkoutInfo.total : this.total;
				
				// 【关键修复】深拷贝total对象，避免修改原始对象，并确保 card 字段正确传递
				const totalForRequest = JSON.parse(JSON.stringify(latestTotal));
				totalForRequest.surplus = surplusAmount;
				totalForRequest.surplus_formated = this.currency + this.formatCurrencyValue(surplusAmount);
				
				// 【关键修复】确保 card 字段正确传递：设置为当前选中储值卡的余额
				// 获取当前选中储值卡的余额
				const activeCardId = this.valueCardObject.valueCardBase ? this.tempValueCardId : this.valueCardObject.valueCardId;
				if (activeCardId > 0 && this.checkoutInfo && this.checkoutInfo.value_card) {
					const selectedCard = this.checkoutInfo.value_card.find(card => Number(card.vid) === Number(activeCardId));
					if (selectedCard) {
						const cardBalance = Number(selectedCard.card_money || 0);
						totalForRequest.card = this.moneyPrecision(cardBalance);
					}
				}

				// free_shipping_fee 以后端计算接口（changecou/changecard/changesurplus/积分等）返回值为准，不从前端 formated 反推
				
				uni.request({
					url: this.websiteUrl + '/api/trade/changesurplus',
					method: 'POST',
					data: {
						total: totalForRequest,
						surplus: surplusAmount,
						shipping_id: this.shipping_id,
						// 【关键修复】如果有优惠券并且使用的情况，传递已选中的优惠券ID
						uc_id: (this.couponsObject.couponsIdArr && this.couponsObject.couponsIdArr.length > 0) ? this.couponsObject.couponsIdArr : []
					},
						header: {
							'Content-Type': 'application/json',
							'token': uni.getStorageSync('token'),
							'X-Client-Hash': uni.getStorageSync('client_hash')
						},
						success: (res) => {
							const { data, status } = res.data;
							if (status === 'failed') {
								reject({ status: 'failed', data });
								return;
							}
							const normalized = this.mergeValueCardData(data, 'changesurplus');
							this.$store.dispatch('setCheckoutTotal', normalized);
							this.amountPrice = normalized.amount;
							this.total.surplus = normalized.surplus;
							this.total.surplus_formated = normalized.surplus_formated;
							this.surplus = normalized.surplus;
							resolve({ status: 'success', data: normalized });
						},
						fail: (error) => {
							reject({ status: 'failed', error });
						}
					});
				});
			},
			// 积分接口 Promise 版本
			integralSelfHandlePromise() {
				return new Promise((resolve, reject) => {
					if (!this.use_integral_val || this.use_integral_val === 0) {
