						},
						fail: (error) => {
							reject({ status: 'failed', error });
						}
					});
				});
			},
			// 红包接口 Promise 版本
			submitBonusPromise() {
				return new Promise((resolve, reject) => {
					const bonusId = this.bonusObject.bonusId || 0;
					
					if (bonusId === 0) {
						resolve({ status: 'success', skip: true });
						return;
					}
					
					const latestTotal = this.checkoutInfo && this.checkoutInfo.total ? this.checkoutInfo.total : this.total;
					
					uni.request({
						url: this.websiteUrl + '/api/trade/changebon',
						method: 'POST',
						data: {
							bonus_id: bonusId,
							total: latestTotal,
							shipping_id: this.shipping_id
						},
						header: {
							'Content-Type': 'application/json',
							'token': uni.getStorageSync('token'),
							'X-Client-Hash': uni.getStorageSync('client_hash')
						},
						success: ({ data: { data, status } }) => {
							if (status === 'failed') {
								reject({ status: 'failed', data });
								return;
							}
							const normalized = this.mergeValueCardData(data, 'submitBonus');
							this.$store.dispatch('setCheckoutTotal', normalized);
							this.amountPrice = normalized.amount;
							this.total.bonus_money = normalized.bonus_money;
							this.bonusObject.bonusMoney = normalized.bonus_money;
							if (normalized.bonus_money > 0) {
								this.bonusObject.bonusContent = normalized.bonus_money_formated;
							} else {
								this.bonusObject.bonusContent = this.$t('lang.no_use_bonus');
							}
							resolve({ status: 'success', data: normalized });
						},
						fail: (error) => {
							reject({ status: 'failed', error });
						}
					});
				});
			},
			//储值卡选择
			valueCardActive(id) {
				// 【关键修复】在弹窗中切换选中时，只更新临时状态 tempValueCardId，不更新实际状态 valueCardObject.valueCardId
				// 只有点击确定后，才会将 tempValueCardId 同步到 valueCardObject.valueCardId
				if (this.tempValueCardId != id) {
					this.tempValueCardId = id
					// 用户重新选择了储值卡，清除取消标记
					this.userValueCardCancelled = false
				} else {
					this.tempValueCardId = 0
					// 用户取消了储值卡，设置取消标记
					this.userValueCardCancelled = true
				}
			},
			//储值卡确认
			submitValuecard() {
				// 【关键修复】使用临时状态 tempValueCardId 作为请求参数
				// 【关键修复】直接使用 checkoutInfo.total 而不是 this.total，确保获取最新的值（包括 coupons_money、integral 等）
				const latestTotal = this.checkoutInfo && this.checkoutInfo.total ? this.checkoutInfo.total : this.total;

				// 【关键修复】深拷贝total对象，避免修改原始对象，并确保 card 字段正确传递
				const totalForRequest = JSON.parse(JSON.stringify(latestTotal));

				// 【关键修复】动态设置 card 字段为当前选中储值卡的余额，而不是依赖 checkoutInfo.total.card 的值
				// 获取当前选中储值卡的余额
				const activeCardId = this.valueCardObject.valueCardBase ? this.tempValueCardId : this.valueCardObject.valueCardId;
				if (activeCardId > 0 && this.checkoutInfo && this.checkoutInfo.value_card) {
					const selectedCard = this.checkoutInfo.value_card.find(card => Number(card.vid) === Number(activeCardId));
					if (selectedCard) {
						const cardBalance = Number(selectedCard.card_money || 0);
						totalForRequest.card = this.moneyPrecision(cardBalance);
					}
				}

				// free_shipping_fee 以后端计算接口返回值为准，不从前端 formated 反推

				const payload = {
					vid: this.tempValueCardId,
					total: totalForRequest,
					shipping_id: this.shipping_id,
					// 【关键修复】如果有优惠券并且使用的情况，传递已选中的优惠券ID
					uc_id: (this.couponsObject.couponsIdArr && this.couponsObject.couponsIdArr.length > 0) ? this.couponsObject.couponsIdArr : []
				};
				uni.request({
					url: this.websiteUrl + '/api/trade/changecard',
					method: 'POST',
					data: payload,
					header: {
						'Content-Type': 'application/json',
						'token': uni.getStorageSync('token'),
						'X-Client-Hash': uni.getStorageSync('client_hash')
					},
					success: ({
						data: {
							data
						}
					}) => {
						// 【关键修复】完全使用后端返回的 amount，不再保留原来的金额
						// 后端返回的 data.amount 已经包含了所有扣款（储值卡、优惠券、折扣、余额等）
						// 直接使用接口返回的 data，不再替换 amount
						const normalized = this.mergeValueCardData(data, 'submitValuecard');
						this.$store.dispatch('setCheckoutTotal', normalized);
						
						// 【关键修复】直接使用后端返回的 amount 更新总金额
						this.amountPrice = normalized.amount;

					if (data.card_money > 0) {
						this.valueCardObject.valueCardContent = data.card_formated
						// 用户成功使用了储值卡，清除取消标记
						this.userValueCardCancelled = false
					} else {
						this.valueCardObject.valueCardContent = this.$t('lang.no_use_value_card')
						// 用户取消了储值卡（金额为0），设置取消标记
						if (data.value_card_id == 0 || this.valueCardObject.valueCardId == 0) {
							this.userValueCardCancelled = true
						}
					}

					this.valueCardObject.vc_dis = data.vc_dis

					// 储值卡扣款以后端返回的 card_money 为准
					if (normalized.value_card_id > 0 && !this.userValueCardCancelled) {
						const cardMoney = this.moneyPrecision(Number(normalized.card_money) || 0);
						this.valueCardObject.valueCardMoney = cardMoney;
						if (cardMoney > 0) {
							this.valueCardObject.valueCardContent = normalized.card_money_formated || (this.currency + this.formatCurrencyValue(cardMoney));
							this.userValueCardCancelled = false;
						} else {
							this.valueCardObject.valueCardContent = this.$t('lang.no_use_value_card');
						}
						this.valueCardObject.valueCardId = normalized.value_card_id;
					} else {
						if (this.userValueCardCancelled) {
							this.valueCardObject.valueCardId = 0;
						}
						this.valueCardObject.valueCardMoney = 0;
						this.valueCardObject.valueCardContent = this.$t('lang.no_use_value_card');
					}
					this.valueCardObject.vc_dis_money = normalized.vc_dis_money || this.valueCardObject.vc_dis_money;
					this.valueCardObject.vc_dis = normalized.vc_dis || this.valueCardObject.vc_dis;
					// 同步临时状态到实际状态
					this.tempValueCardId = data.value_card_id
					// 如果接口返回 value_card_id = 0，说明用户取消了，设置取消标记
					if (data.value_card_id == 0) {
						this.userValueCardCancelled = true
					}
					this.getType = false
					this.prioritySelectingValueCard = false
					this.autoPriorityApplied = false
						if (!this.persistValueCardFromResponse(data, 'submitValuecard success')) {
							this.clearPersistedValueCard('submitValuecard cleared');
						}
						this.$nextTick(() => {
							this.ensurePaymentPriority();
							// 【方案1】储值卡切换/关闭后，若余额/先用后付已开启，重新计算 先用后付 金额
							if (this.balancePaymentActive) {
								this.surplusvValHandle();
							}
						});
					},
					fail: (error) => {
						this.prioritySelectingValueCard = false
						this.$nextTick(() => {
							this.ensurePaymentPriority();
						});
					}
				})

				this.valueCardObject.valueCardBase = false
				this.surplus_status = false
			},
			
			
			
			  // 自动选择储值卡
			  autoSelectValueCard(currentPrice) {
			    // 确保有储值卡数据且当前没有选中任何储值卡
			    const selectedCardId = Number(this.valueCardObject && this.valueCardObject.valueCardId ? this.valueCardObject.valueCardId : 0);
			    if (this.valueCartInfo.card_list && this.valueCartInfo.card_list.length > 0 && selectedCardId <= 0) {
			      
			      // 将价格转换为数字类型进行比较
			      const price = Number(currentPrice);
			      
			      // 查找可用的储值卡，按面值从大到小排序
			      const availableCards = this.valueCartInfo.card_list
			        .filter(card => {
			          const cardMoney = Number(card.use_card_money);
			          return cardMoney > 0 && cardMoney <= price;
			        })
			        .sort((a, b) => Number(b.use_card_money) - Number(a.use_card_money));
			      
			      // 如果有合适的储值卡，选择面值最大的那个
			      if (availableCards.length > 0) {
			        const bestCard = availableCards[0];
			        this.valueCardObject.valueCardId = bestCard.vid;
			        // 【关键修复】如果弹窗打开，同时更新临时状态
			        if (this.valueCardObject.valueCardBase) {
			          this.tempValueCardId = bestCard.vid;
			        }
			        
			        // 自动提交储值卡选择
			        this.submitSelectedValueCard();
			      } else {
			        // 如果没有合适的储值卡，可以选择面值最小的（可选）
			        this.selectSmallestValueCard(price);
			      }
			    }
			  },
			  findBestValueCard(currentPrice) {
			    if (!this.valueCartInfo || !Array.isArray(this.valueCartInfo.card_list)) {
			      return null;
			    }

			    const price = Number(currentPrice);
			    if (isNaN(price) || price <= 0) {
			      return null;
			    }

			    const positiveCards = this.valueCartInfo.card_list
			      .filter(card => Number(card.use_card_money) > 0);

			    if (positiveCards.length === 0) {
			      return null;
			    }

			    const coveringCards = positiveCards
			      .filter(card => Number(card.use_card_money) >= price)
			      .sort((a, b) => Number(a.use_card_money) - Number(b.use_card_money));

			    if (coveringCards.length > 0) {
			      return coveringCards[0];
			    }

			    const usableCards = positiveCards
			      .filter(card => Number(card.use_card_money) <= price)
			      .sort((a, b) => Number(b.use_card_money) - Number(a.use_card_money));

			    if (usableCards.length > 0) {
			      return usableCards[0];
			    }

			    return positiveCards
			      .sort((a, b) => Number(a.use_card_money) - Number(b.use_card_money))[0] || null;
			  },
			  
			  // 选择面值最小的储值卡（当没有完全覆盖的储值卡时）
			  selectSmallestValueCard(currentPrice) {
			    const availableCards = this.valueCartInfo.card_list
			      .filter(card => Number(card.use_card_money) > 0)
			      .sort((a, b) => Number(a.use_card_money) - Number(b.use_card_money));
			    
			    if (availableCards.length > 0) {
			      const smallestCard = availableCards[0];
			      this.valueCardObject.valueCardId = smallestCard.vid;
			      // 【关键修复】如果弹窗打开，同时更新临时状态
			      if (this.valueCardObject.valueCardBase) {
			        this.tempValueCardId = smallestCard.vid;
			      }
			      
			      // 自动提交储值卡选择
			      this.submitSelectedValueCard();
			    }
			  },
			  
			  // 提交选中的储值卡
			  submitSelectedValueCard() {
			    if (this.valueCardObject.valueCardId && this.valueCardObject.valueCardId !== 0) {
			      // 延迟执行，确保数据更新完成
			      setTimeout(() => {
			        this.submitValuecard();
			      }, 100);
			    }
			  },
			  applyDefaultValueCard() {
			    const list = this.valueCartInfo && this.valueCartInfo.card_list ? this.valueCartInfo.card_list : [];
			    if (!list.length) {
			      return;
			    }

			    // 【关键修复】如果用户明确取消了储值卡，不再自动应用
			    if (this.userValueCardCancelled) {
			      return;
			    }

			    const selectedId = Number(this.valueCardObject && this.valueCardObject.valueCardId ? this.valueCardObject.valueCardId : 0);
			    if (selectedId > 0) {
			      return;
			    }
			    // 选卡时用「扣储值卡前应付款」计算，不用 total.amount
			    const latestTotalAuto = this.checkoutInfo && this.checkoutInfo.total ? this.checkoutInfo.total : this.total;
			    const goodsPriceAuto = this.moneyPrecision(parseFloat(latestTotalAuto && latestTotalAuto.goods_price ? latestTotalAuto.goods_price : 0) || 0);
			    const baseAuto = goodsPriceAuto > 0 ? goodsPriceAuto : (this.price && this.price > 0 ? this.moneyPrecision(parseFloat(this.price) || 0) : 0);
			    const shippingAuto = this.shippingFee ? Number(this.shippingFee) : 0;
			    const couponsAuto = Number(this.couponsObject && this.couponsObject.couponsMoney ? this.couponsObject.couponsMoney : 0);
			    const discountAuto = Number(latestTotalAuto && latestTotalAuto.discount) || 0;
			    const bonusAuto = Number(latestTotalAuto && latestTotalAuto.bonus_money) || Number(this.bonusObject && this.bonusObject.bonusMoney) || 0;
			    const integralAuto = Number(latestTotalAuto && latestTotalAuto.integral_money) || 0;
			    const amountDue = this.moneyPrecision(Math.max(0, baseAuto + shippingAuto - couponsAuto - discountAuto - bonusAuto - integralAuto));
			    let bestCard = this.findBestValueCard(amountDue);

			    if (!bestCard) {
			      bestCard = list[0];
			    }

			    if (bestCard && bestCard.vid) {
			      this.valueCardObject.valueCardId = Number(bestCard.vid) || 0;
			      // 【关键修复】如果弹窗打开，同时更新临时状态
			      if (this.valueCardObject.valueCardBase) {
			        this.tempValueCardId = Number(bestCard.vid) || 0;
			      }
			      this.valueCardObject.valueCardMoney = 0;
			      this.valueCardObject.valueCardContent = this.$t ? this.$t('lang.loading') : '加载中...';
			      this.pendingValueCardApplyId = Number(bestCard.vid) || 0;
			      this.tryApplyPendingValueCard();
			    }
			  },
			  clearValueCardApplyTimer() {
			    if (this.valueCardApplyTimer) {
			      clearTimeout(this.valueCardApplyTimer);
			      this.valueCardApplyTimer = null;
			    }
			  },
			  clearValueCardLoadRetry() {
			    if (this.valueCardLoadRetryTimer) {
			      clearTimeout(this.valueCardLoadRetryTimer);
			      this.valueCardLoadRetryTimer = null;
			    }
			  },
			  resetValueCardLoadRetry() {
			    this.clearValueCardLoadRetry();
			    this.valueCardLoadRetryAttempts = 0;
			  },
			  scheduleValueCardLoadRetry(reason = '') {
			    const maxAttempts = 30;
			    if (!this.pageActive) {
			      return;
			    }
			    if (this.valueCardLoadRetryAttempts >= maxAttempts) {
			      return;
			    }
			    this.valueCardLoadRetryAttempts += 1;
			    this.clearValueCardLoadRetry();
			    this.valueCardLoadRetryTimer = setTimeout(() => {
			      this.valueCardLoad();
			    }, 200);
			  },
			  isShippingReady() {
			    if (this.store_id > 0) {
			      return true;
			    }
			    if (Array.isArray(this.shipping_id) && this.shipping_id.length > 0) {
			      return true;
			    }
			    if (!Array.isArray(this.shipping_id) && this.shipping_id) {
			      return true;
			    }
			    if (this.checkoutInfo && this.checkoutInfo.total) {
			      if (Number(this.checkoutInfo.total.real_goods_count || 0) === 0) {
			        return true;
			      }
			    }
			    return false;
			  },
			  tryApplyPendingValueCard(retry = true) {
			    if (!this.pendingValueCardApplyId) {
			      return;
			    }
			    if (!this.pageActive) {
			      this.pendingValueCardApplyId = 0;
			      this.valueCardApplyAttempts = 0;
			      this.prioritySelectingValueCard = false;
			      return;
			    }
			    if (!this.isShippingReady()) {
			      if (retry) {
			        if (this.valueCardApplyAttempts >= this.maxValueCardApplyAttempts) {
			          this.pendingValueCardApplyId = 0;
			          this.prioritySelectingValueCard = false;
			          return;
			        }
			        this.valueCardApplyAttempts += 1;
			        this.clearValueCardApplyTimer();
			        this.valueCardApplyTimer = setTimeout(() => {
			          this.tryApplyPendingValueCard();
			        }, 120);
			      }
			      return;
			    }

			    this.clearValueCardApplyTimer();
			    this.valueCardApplyAttempts = 0;
			    const targetId = this.pendingValueCardApplyId;
			    this.pendingValueCardApplyId = 0;
			    if (targetId > 0) {
			      this.prioritySelectingValueCard = true;
			      this.valueCardObject.valueCardId = targetId;
			      // 【关键修复】无论弹窗是否打开，都同步更新临时状态，确保显示正确
			      this.tempValueCardId = targetId;
			      this.submitSelectedValueCard();
			    }
			  },
			
			
			//运费展开
			feeHandle(val, id, item) {
				this.freepopuData = item.goods
				this.pop_shipping_fee = item.shipping.default_shipping.shipping_fee
				let ru_id = 0
				let rec_ids = ''
				let flow_type = this.checkoutInfo.flow_type
				let shipping_region = {
					country: 1,
					province: this.checkoutInfo.consignee.province,
					city: this.checkoutInfo.consignee.city,
					district: this.checkoutInfo.consignee.district,
					street: this.checkoutInfo.consignee.street
				}

				this.feeShow = true
				this.shipping_active_id = val
				this.checkoutInfo.goods_list[val].goods.forEach((v) => {
					rec_ids += v.rec_id + ','
					ru_id = v.ru_id
				})

				rec_ids = rec_ids.substr(0, rec_ids.length - 1)

				this.$store.dispatch('setShipping', {
					rec_ids: rec_ids,
					ru_id: ru_id,
					consignee: JSON.stringify(shipping_region),
					flow_type: flow_type
				}).then(({
					data: data
				}) => {
					if (data.shipping) {
						this.shippingList = data.shipping
					}
				})
			},
			//选择配送方式
			shipping_select(item) {

				if (!this.balancePaymentActive) {
					this.use_surplus_val = 0
					this.use_credit_val = 0
				}

				this.shipping_id.splice(this.shipping_active_id, 1, item.shipping_id)
				this.shipping_code.splice(this.shipping_active_id, 1, item.shipping_code)
				this.shipping_name.splice(this.shipping_active_id, 1, item.shipping_name)
				this.shipping_fee.splice(this.shipping_active_id, 1, item.shipping_fee)
				this.format_shipping_fee.splice(this.shipping_active_id, 1, item.format_shipping_fee)
				this.rate_price.splice(this.shipping_active_id, 1, item.rate_price)

				//关闭弹窗
				this.handelClose('fee');
			},
			//展开支付方式
			paymentSelect() {
				// 如果当前是余额/用后付，提示用户使用顶部开关
				if (this.balancePaymentActive) {
					uni.showToast({
						title: '请使用顶部"余额/先用后付"开关切换支付方式',
						icon: 'none',
						duration: 2000
					});
					return;
				}
				this.paymentShow = true

				setTimeout(() => {
					this.tipscroll = true
				}, 500)
			},
			//余额/先用后付开关
			balanceToggleChange(e) {
				const enabled = e.detail.value === true;
				const previousState = this.balancePaymentActive;
				
				// #ifdef MP-WEIXIN
				// 微信小程序兼容性处理：即使 disabled=true，change 事件仍可能触发
				// 需要在方法开始处立即检查并同步重置状态，确保开关不会显示为开启
				if (this.balanceToggleDisabled) {
					const message = this.balanceToggleDisabledReason || '已自动选择支付方式';
					uni.showToast({
						title: message,
						icon: 'none'
					});
					// 立即同步重置状态，不使用 $nextTick，确保立即生效
					this.use_surplus_val = 0;
					this.surplusSelf = false;
					this.balanceSwitchVersion++;
					// 强制更新视图，确保开关状态立即恢复
					this.$forceUpdate();
					return;
				}
				// #endif
				
				// #ifndef MP-WEIXIN
				// APP 和 H5：disabled 状态下不会触发 change 事件，但保留检查以防万一
				if (this.balanceToggleDisabled) {
					const message = this.balanceToggleDisabledReason || '已自动选择支付方式';
					uni.showToast({
						title: message,
						icon: 'none'
					});
					this.use_surplus_val = 0;
					this.$nextTick(() => {
						this.surplusSelf = false;
						this.balanceSwitchVersion++;
					});
					return;
				}
				// #endif
				
				if (this.initializingPaymentToggles) {
					this.use_surplus_val = 0;
					this.$nextTick(() => {
						this.surplusSelf = false;
						this.balanceSwitchVersion++;
					});
					return;
				}
				
				const selectedCardId = Number(this.valueCardObject && this.valueCardObject.valueCardId ? this.valueCardObject.valueCardId : 0);
				const valueCardMoney = Number(this.valueCardObject && this.valueCardObject.valueCardMoney ? this.valueCardObject.valueCardMoney : 0);
				const hasValueCardSelected = selectedCardId > 0 && valueCardMoney > 0;
				const amountDue = this.moneyPrecision(parseFloat(this.total && this.total.amount !== undefined ? this.total.amount : 0) || 0);
				if (hasValueCardSelected && amountDue <= 0 && enabled) {
					uni.showToast({
						title: '已使用储值卡完成支付',
						icon: 'none'
					});
					this.use_surplus_val = 0;
					this.$nextTick(() => {
						this.surplusSelf = false;
						this.balanceSwitchVersion++;
					});
					return;
				}
				this.userBalanceModified = true;
				this.autoPriorityApplied = true;
				const success = this.toggleBalancePayment(enabled);
				if (!success) {
					this.$nextTick(() => {
						this.use_surplus_val = enabled ? 0 : 1;
					});
					return;
				}
				if (!enabled) {
					if (this.use_credit_val === 1) {
						this.toggleCreditPayment(false, {
							silent: true
						});
					}
					this.use_credit_val = 0;
					this.surplus_credit_line = 0;
					this.userCreditModified = true;
					this.creditToggleDisabled = false;
					this.creditToggleDisabledReason = '';
				} else {
					this.balanceToggleDisabled = false;
					this.balanceToggleDisabledReason = '';
				}
				if (!enabled) {
					this.userCreditModified = true;
				}
			},
			creditToggleChange(e) {
				const enabled = e.detail ? e.detail.value === true : e;
				const previousState = this.use_credit_val === 1;
				
				// #ifdef MP-WEIXIN
				// 微信小程序兼容性处理：即使 disabled=true，change 事件仍可能触发
				// 需要在方法开始处立即检查并同步重置状态，确保开关不会显示为开启
				if (this.creditToggleDisabled) {
					const message = this.creditToggleDisabledReason || '已自动选择支付方式';
					uni.showToast({
						title: message,
						icon: 'none'
					});
					// 立即同步重置状态，不使用 $nextTick，确保立即生效
					this.use_credit_val = 0;
						this.creditSelf = false;
						this.creditSwitchVersion++;
					// 强制更新视图，确保开关状态立即恢复
					this.$forceUpdate();
					return;
				}
				// #endif
				
				// #ifndef MP-WEIXIN
				// APP 和 H5：disabled 状态下不会触发 change 事件，但保留检查以防万一
				if (this.creditToggleDisabled) {
					const message = this.creditToggleDisabledReason || '已自动选择支付方式';
					uni.showToast({
						title: message,
						icon: 'none'
					});
					this.use_credit_val = 0;
					this.$nextTick(() => {
						this.creditSelf = false;
						this.creditSwitchVersion++;
					});
					return;
				}
				// #endif
				
				if (this.initializingPaymentToggles) {
					this.use_credit_val = 0;
					this.$nextTick(() => {
						this.creditSelf = false;
						this.creditSwitchVersion++;
					});
					return;
				}
			// 【修复】在检查前，先确保 payment_info 是最新的（特别是取消储值卡后）
			// 【关键修复】无论余额是否开启，都应该先更新 payment_info，确保基于最新的储值卡状态计算
			// 如果余额开启，调用 applyBalancePaymentState 更新 payment_info
			// 如果余额未开启，也需要更新 payment_info，因为取消储值卡后，剩余金额可能变化
			// 【关键修复】关闭弹窗时不应该计算，只有用户点击确定时才更新计算
			// 因此，在 creditToggleChange 中，应该基于已确认的 checkoutInfo.total.value_card_id 来计算
			// 而不是基于弹窗中临时修改的 valueCardObject.valueCardId
			if (this.balancePaymentActive) {
				this.applyBalancePaymentState({ silent: true });
			} else {
				// 【修复】余额未开启时，也需要更新 payment_info；计算只用商品金额，不用 total.amount
				const latestTotal = this.checkoutInfo && this.checkoutInfo.total ? this.checkoutInfo.total : this.total;
				const goodsPrice = this.moneyPrecision(parseFloat(latestTotal && latestTotal.goods_price ? latestTotal.goods_price : 0) || 0);
				const baseAmount = goodsPrice > 0 ? goodsPrice : (this.price && this.price > 0 ? this.moneyPrecision(parseFloat(this.price) || 0) : 0);
				const shippingFee = this.shippingFee ? Number(this.shippingFee) : 0;
				const couponsMoney = Number(this.couponsObject && this.couponsObject.couponsMoney ? this.couponsObject.couponsMoney : 0);
				const discount = Number(latestTotal && latestTotal.discount) || 0;
				const bonusMoney = Number(latestTotal && latestTotal.bonus_money) || Number(this.bonusObject && this.bonusObject.bonusMoney) || 0;
				const integralMoney = Number(latestTotal && latestTotal.integral_money) || 0;
				const confirmedValueCardId = Number(this.checkoutInfo && this.checkoutInfo.total && this.checkoutInfo.total.value_card_id ? this.checkoutInfo.total.value_card_id : 0);
				const valueCardMoney = this.calculateValueCardMoneyByCardId(confirmedValueCardId);
				const totalAmount = this.moneyPrecision(Math.max(0, baseAmount + shippingFee - couponsMoney - discount - bonusMoney - integralMoney - valueCardMoney));
				this.resetPaymentStatus(totalAmount);
				}
				const remainingAfterBalance = this.moneyPrecision(this.payment_info && this.payment_info.remaining_debt !== undefined ? this.payment_info.remaining_debt : 0);
				const alreadyCoveredByBalance = this.balancePaymentActive && remainingAfterBalance <= 0;
				if (alreadyCoveredByBalance && enabled) {
					uni.showToast({
						title: '储值卡/余额已完成支付',
						icon: 'none'
					});
					this.use_credit_val = 0;
					this.surplus_credit_line = 0;
					this.$nextTick(() => {
						this.creditSelf = false;
						this.creditSwitchVersion++;
					});
					return;
				}
				this.userCreditModified = true;
				this.autoPriorityApplied = true;
				// 如果余额值大于0，用后付需要跟随余额开启；如果余额值小于等于0，用后付可以独立开启
				if (!this.balancePaymentActive && this.balance_money_available > 0) {
					if (enabled) {
						this.use_credit_val = 0;
						this.surplus_credit_line = 0;
						uni.showToast({
							title: '请先使用余额',
							icon: 'none'
						});
						this.$nextTick(() => {
							this.creditSelf = false;
							this.creditSwitchVersion++;
						});
					} else {
						this.use_credit_val = 0;
						this.surplus_credit_line = 0;
					}
					return;
				}
				const success = this.toggleCreditPayment(enabled);
				if (!success) {
					this.$nextTick(() => {
						this.use_credit_val = enabled ? 0 : 1;
					});
				}
			},
			//选择支付方式（仅用于弹窗选择，余额/用后付已通过顶部开关控制）
			payment_method_select(id, name, code, useList, options = {}) {
				// 禁止从弹窗选择余额/用后付
				if (id == 11 || name === this.balancePaymentLabel) {
					uni.showToast({
						title: '请使用顶部"余额/先用后付"开关切换',
						icon: 'none',
						duration: 2000
					});
					return;
				}

				// 记录当前选择的支付方式
				const paymentOption = {
					pay_id: id,
					pay_name: name,
					pay_code: code,
					use_list: useList || {}
				};

				// 更新支付方式
				this.pay_id = paymentOption.pay_id;
				this.pay_name = paymentOption.pay_name;
				this.pay_code = paymentOption.pay_code;
				this.submit_pay_id = paymentOption.pay_id;
				this.submit_pay_code = paymentOption.pay_code;
				this.payDisplayName = paymentOption.pay_name;
				this.balancePaymentActive = false;
				this.use_surplus_val = 0; // 【修复】与balancePaymentActive严格同步
				this.balance_money = 0;
				this.surplus_credit_line = 0;
				this.use_credit_val = 0; // 【修复】与信用付状态严格同步
				this.princeType = false;

				// 记录非余额支付方式，以便顶部开关关闭时恢复
				this.rememberLastNonBalancePayment(paymentOption);

				// 重置支付状态
				const resetAmountSource = this.total && this.total.amount !== undefined ? this.total.amount :
					this.payment_info.original_price || 0;
				const resetAmount = this.moneyPrecision(parseFloat(resetAmountSource) || 0);
				this.resetPaymentStatus(resetAmount);
				this.pay_yue_full = false;
				this.pay_yue_credit = false;
				this.pay_surplus = false;
				this.pay_no = false;

				// 关闭弹窗
				this.handelClose('payment');
			},
			//使用余额（与当前余额/信用付逻辑联动，统一走 changesurplus 接口）
			surplusvValHandle(e) {
				// 【关键修复】防止重复调用，如果已经有请求在进行中，标记需要重试，等当前请求完成后再用最新状态发一次
				if (this.surplusvValHandlePending) {
					console.log('[surplusvValHandle] 请求正在进行中，标记完成后重试');
					this.surplusvValHandleNeedsRetry = true;
					return;
				}
				
				// 设置标志，防止重复调用
				this.surplusvValHandlePending = true;
				
				// 【关键修复】记录当前开关状态，用于调试
				console.log('[surplusvValHandle] 当前开关状态 - balancePaymentActive:', this.balancePaymentActive, 'use_surplus_val:', this.use_surplus_val, 'use_credit_val:', this.use_credit_val);
				
				// 1. 计算当前应提交给后端的余额和信用付总和
				// 【关键修复】surplus 参数是余额和信用付共用的，需要计算两者的总和
				// 根据余额和信用付的开关状态，分别获取实际使用的金额，然后计算总和
				// 【重要】必须严格按照开关状态判断，关闭时强制为 0，不使用任何缓存值
				let balanceAmount = 0; // 余额实际使用金额
				let creditAmount = 0;  // 信用付实际使用金额
				
				// 计算余额金额：根据余额开关状态（balancePaymentActive 和 use_surplus_val）
				// 【关键修复】必须同时检查 balancePaymentActive 和 use_surplus_val，确保只有在两个条件都满足时才计算余额金额
				// 关闭时强制为 0，不使用任何缓存值
				if (this.balancePaymentActive && this.use_surplus_val === 1) {
					// 优先使用 payment_info.used_balance（如果已计算），否则使用 balance_money
					if (this.payment_info && this.payment_info.used_balance && Number(this.payment_info.used_balance) > 0) {
						balanceAmount = Number(this.payment_info.used_balance);
					} else if (this.balance_money && Number(this.balance_money) > 0) {
						balanceAmount = Number(this.balance_money);
					} else {
						// 【关键修复】如果 balance_money 为 0，不应该使用 this.surplus（可能是旧值），应该为 0
						balanceAmount = 0;
					}
				} else {
					// 【关键修复】余额开关关闭时（balancePaymentActive 为 false 或 use_surplus_val 不为 1），强制余额金额为 0，不使用任何缓存值
					balanceAmount = 0;
				}
				
				// 计算信用付金额：根据信用付开关状态（use_credit_val === 1）
				// 【关键】顺序：储值卡 → 余额 → 先用后付。基数 = 应付款 - 折扣 - 红包 - 积分 - 储值卡，再扣余额后的剩余才用信用付
				if (this.use_credit_val === 1) {
					const latestTotal = this.checkoutInfo && this.checkoutInfo.total ? this.checkoutInfo.total : this.total;
					const goodsPrice = latestTotal && latestTotal.goods_price ? Number(latestTotal.goods_price) : 0;
					const shippingFee = this.shippingFee ? Number(this.shippingFee) : 0;
					const couponsMoney = Number(this.couponsObject && this.couponsObject.couponsMoney ? this.couponsObject.couponsMoney : 0);
					const discount = Number(latestTotal && latestTotal.discount) || 0;
					const bonusMoney = Number(latestTotal && latestTotal.bonus_money) || Number(this.bonusObject && this.bonusObject.bonusMoney) || 0;
					const integralMoney = Number(latestTotal && latestTotal.integral_money) || 0;
					const valueCardMoney = this.getValueCardMoney();
					// 应付款（商品+运费-优惠券-折扣-红包-积分）- 储值卡 = 余额和先用后付的基数（与 applyBalancePaymentState 顺序一致）
					const amountAfterValueCard = this.moneyPrecision(Math.max(0, goodsPrice + shippingFee - couponsMoney - discount - bonusMoney - integralMoney - valueCardMoney));
					// 扣除余额后的剩余，再用信用付覆盖
					const remainingAfterBalance = this.moneyPrecision(Math.max(0, amountAfterValueCard - balanceAmount));
					const availableCredit = this.moneyPrecision(Math.max(this.surplus_credit_line_available || 0, 0));
					
					if (remainingAfterBalance > 0 && availableCredit > 0) {
						creditAmount = this.moneyPrecision(Math.min(availableCredit, remainingAfterBalance));
					} else {
						creditAmount = 0;
					}
				} else {
					// 【关键修复】信用付开关关闭时（use_credit_val !== 1），强制信用付金额为 0，不使用任何缓存值
					creditAmount = 0;
				}
				
				// 计算总和：余额 + 信用付
				const surplusAmount = this.moneyPrecision(balanceAmount + creditAmount);
				
				// 【关键修复】记录计算出的值，用于调试
				console.log('[surplusvValHandle] 计算出的值 - balanceAmount:', balanceAmount, 'creditAmount:', creditAmount, 'surplusAmount:', surplusAmount);
				
				// 【关键修复】同步更新本地状态，确保后续计算使用正确的值
				this.surplus = surplusAmount;
				// 同步更新surplus_credit_line，避免后续计算使用旧值
				if (this.use_credit_val === 1) {
					this.surplus_credit_line = this.moneyPrecision(creditAmount);
					// 同步更新payment_info.used_credit
					if (this.payment_info) {
						if (!this.payment_info.used_credit || this.payment_info.used_credit !== creditAmount) {
							this.$set(this.payment_info, 'used_credit', this.moneyPrecision(creditAmount));
						}
					}
				} else {
					this.surplus_credit_line = 0;
				}

			// 2. 选择要传递给后端的 total（优先使用 checkoutInfo.total）
			const latestTotal = this.checkoutInfo && this.checkoutInfo.total ? this.checkoutInfo.total : this.total;
			
			// 【关键修复】深拷贝total对象，避免修改原始对象，并更新surplus值为计算出的总和
			const totalForRequest = JSON.parse(JSON.stringify(latestTotal));
			totalForRequest.surplus = surplusAmount;
			totalForRequest.surplus_formated = this.currency + this.formatCurrencyValue(surplusAmount);
			
			// 【关键修复】确保 card 字段正确传递：设置为当前选中储值卡的余额
			// 获取当前选中储值卡的余额
			const activeCardId = this.valueCardObject.valueCardBase ? this.tempValueCardId : this.valueCardObject.valueCardId;
			if (activeCardId > 0 && this.checkoutInfo && this.checkoutInfo.value_card) {
				const selectedCard = this.checkoutInfo.value_card.find(card => Number(card.vid) === Number(activeCardId));
				if (selectedCard) {
					const cardBalance = Number(selectedCard.card_money || 0);
					totalForRequest.card = this.moneyPrecision(cardBalance);
				}
			}

			// free_shipping_fee 以后端计算接口返回值为准，不从前端 formated 反推
				
			uni.request({
				url: this.websiteUrl + '/api/trade/changesurplus',
				method: 'POST',
				data: {
					total: totalForRequest,
					surplus: surplusAmount,
					shipping_id: this.shipping_id,
					// 【关键修复】如果有优惠券并且使用的情况，传递已选中的优惠券ID
					uc_id: (this.couponsObject.couponsIdArr && this.couponsObject.couponsIdArr.length > 0) ? this.couponsObject.couponsIdArr : []
				},
				header: {
					'Content-Type': 'application/json',
					'token': uni.getStorageSync('token'),
					'X-Client-Hash': uni.getStorageSync('client_hash')
				},
				success: (res) => {
					const normalized = this.mergeValueCardData(res.data.data, 'changesurplus');
						
						// 【关键修复】先直接更新checkoutInfo.total.amount，确保响应式更新
						if (this.checkoutInfo && this.checkoutInfo.total) {
							this.$set(this.checkoutInfo.total, 'amount', normalized.amount);
						}
						
						// 【关键修复】更新payment_info.remaining_debt，确保模板条件判断正确
						// remaining_debt应该是扣除余额和信用付后的剩余应付金额，即normalized.amount
						// 使用$nextTick确保在store更新后更新，避免被覆盖
						this.$store.dispatch('setCheckoutTotal', normalized).then(() => {
							if (this.payment_info) {
								const updatedRemainingDebt = this.moneyPrecision(parseFloat(normalized.amount) || 0);
								this.$set(this.payment_info, 'remaining_debt', updatedRemainingDebt);
								// 强制触发UI更新
								this.$forceUpdate();
							}
						});

						if (normalized.card_money > 0) {
							this.valueCardObject.valueCardContent = normalized.card_formated
						} else {
							this.valueCardObject.valueCardContent = this.$t('lang.no_use_value_card')
						}

						this.amountPrice = normalized.amount
						// 储值卡扣款以后端返回的 card_money 为准
						if (normalized.value_card_id > 0) {
							const cardMoney = this.moneyPrecision(Number(normalized.card_money) || 0);
							this.valueCardObject.valueCardMoney = cardMoney;
							if (cardMoney > 0) {
								this.valueCardObject.valueCardContent = normalized.card_money_formated || (this.currency + this.formatCurrencyValue(cardMoney));
							} else {
								this.valueCardObject.valueCardContent = this.$t('lang.no_use_value_card');
							}
							this.valueCardObject.valueCardId = normalized.value_card_id;
						} else {
							this.valueCardObject.valueCardMoney = 0;
							this.valueCardObject.valueCardContent = this.$t('lang.no_use_value_card');
						}
						this.total.surplus = normalized.surplus
						this.total.surplus_formated = normalized.surplus_formated
						this.surplus = normalized.surplus
						this.surplus_status = true
						this.getType = false	

						this.valueCardObject.vc_dis = normalized.vc_dis
						this.valueCardObject.valueCardId = normalized.value_card_id
						this.persistValueCardFromResponse(normalized, 'changesurplus');
						
						// 【关键修复】清除标志，允许下次调用；若曾因 pending 被跳过，用当前状态再发一次（解决关闭再开启先用后付仍传 46 的问题）
						this.surplusvValHandlePending = false;
						if (this.surplusvValHandleNeedsRetry) {
							this.surplusvValHandleNeedsRetry = false;
							this.$nextTick(() => this.surplusvValHandle());
						}
					},
					fail: (res) => {
						uni.hideLoading();
						this.surplusvValHandlePending = false;
						if (this.surplusvValHandleNeedsRetry) {
							this.surplusvValHandleNeedsRetry = false;
							this.$nextTick(() => this.surplusvValHandle());
						}
					}
				})
			},
			//是否使用积分
			integralSelfHandle(e) {
				this.use_integral_val = e.detail.value == true ? 1 : 0
				uni.showLoading({
					title: this.$t('lang.loading')
				});
				// 【关键修复】直接使用 checkoutInfo.total 而不是 this.total，确保获取最新的值（包括 coupons_money、bonus_money 等）
				const latestTotal = this.checkoutInfo && this.checkoutInfo.total ? this.checkoutInfo.total : this.total;
				uni.request({
					url: this.websiteUrl + '/api/trade/changeint',
					method: 'POST',
					data: {
						total: latestTotal,
						integral_type: this.use_integral_val,
						cart_value: this.cart_id,
						flow_type: this.checkoutInfo.flow_type,
						shipping_id: this.shipping_id,
						// 【关键修复】如果有优惠券并且使用的情况，传递已选中的优惠券ID
						uc_id: (this.couponsObject.couponsIdArr && this.couponsObject.couponsIdArr.length > 0) ? this.couponsObject.couponsIdArr : []
					},
					header: {
						'Content-Type': 'application/json',
						'token': uni.getStorageSync('token'),
						'X-Client-Hash': uni.getStorageSync('client_hash')
					},
					success: (res) => {
						const normalized = this.mergeValueCardData(res.data.data, 'integralSelfHandle');
						this.$store.dispatch('setCheckoutTotal', normalized)

						if (normalized.card_money > 0) {
							this.valueCardObject.valueCardContent = normalized.card_formated

						} else {
							this.valueCardObject.valueCardContent = this.$t('lang.no_use_value_card')
						}

						this.valueCardObject.vc_dis = normalized.vc_dis
						this.amountPrice = normalized.amount
						// 储值卡扣款以后端返回的 card_money 为准
						if (normalized.value_card_id > 0) {
							const cardMoney = this.moneyPrecision(Number(normalized.card_money) || 0);
							this.valueCardObject.valueCardMoney = cardMoney;
							if (cardMoney > 0) {
								this.valueCardObject.valueCardContent = normalized.card_money_formated || (this.currency + this.formatCurrencyValue(cardMoney));
							} else {
								this.valueCardObject.valueCardContent = this.$t('lang.no_use_value_card');
							}
							this.valueCardObject.valueCardId = normalized.value_card_id;
						} else {
							this.valueCardObject.valueCardMoney = 0;
							this.valueCardObject.valueCardContent = this.$t('lang.no_use_value_card');
						}
						this.valueCardObject.vc_dis_money = normalized.vc_dis_money
						this.valueCardObject.valueCardId = normalized.value_card_id
						if (!this.balancePaymentActive) {
							this.use_surplus_val = 0
							this.use_credit_val = 0
						}
						this.getType = false
						this.persistValueCardFromResponse(normalized, 'integralSelfHandle');
						uni.hideLoading();
					},
					fail: (res) => {
						uni.hideLoading();
					}
				})
			},
			// 商品清单
			onListShow(i) {
				this.inventoryShow = true
				let newList = this.checkoutInfo.goods_list.find((item, index) => {
					return item.ru_id == i
				})
				this.inventoryList = newList

			},
			//展开弹出层
			popupHandle(val) {
				if (val == 'bonus') {
					this.bonusObject.bonusBase = true
				} else if (val == 'coupon') {
					this.couponsObject.couponsBase = true
				} else if (val == 'valueCard') {
					// 【关键修复】打开弹窗时，传递 skipEnsurePaymentPriority = true，避免触发自动计算
					this.valueCardLoad(true);
					// 【关键修复】打开弹窗时，初始化临时状态为当前实际状态
					this.tempValueCardId = this.valueCardObject.valueCardId
					this.valueCardObject.valueCardBase = true
				}
				if (!this.balancePaymentActive) {
					this.use_surplus_val = 0
					this.use_credit_val = 0
				}
			},
			//关闭弹出层
			handelClose(val) {
				if (val == 'payment') {
					this.paymentShow = false
				} else if (val == 'fee') {
					this.feeShow = false
				} else if (val == 'bonus') {
					this.bonusObject.bonusBase = false
				} else if (val == 'coupon') {
					this.couponsObject.couponsBase = false
				} else if (val == 'valueCard') {
					// 【关键修复】关闭弹窗时，恢复临时状态为实际状态，丢弃未保存的更改
					// 只有点击确定后，tempValueCardId 才会同步到 valueCardObject.valueCardId
					this.tempValueCardId = this.valueCardObject.valueCardId
					this.valueCardObject.valueCardBase = false
				} else if (val == 'inv') {
					this.showBase = false
				} else if (val == 'quanyi') {
					this.quanyiShow = false
				} else if (val == 'inventory') {
					this.inventoryShow = false
				}
			},
			onSubmit() {
