			couponValClick(id, money, index) {
			  // 确保 couponsId[index] 存在
			  if (!this.couponsObject.couponsId[index]) {
			    this.couponsObject.couponsId[index] = {
			      uc_id: '',
			      cou_money: ''
			    };
			  }
			  
			  // 更新对应店铺的选中状态
			  this.couponsObject.couponsId[index].uc_id = id;
			  this.couponsObject.couponsId[index].cou_money = money;
			  
			  // 重新计算所有选中的优惠券
