		},
		watch: {
			// 监听储值卡金额的变化，用于追踪显示值
			'valueCardObject.valueCardMoney'(newVal, oldVal) {
				// 储值卡金额变化监听（已移除日志）
			},
			checkoutInfo() {
				this.checkoutInfoWatchCount += 1;
				if (this.checkoutInfo.length == 0) {
					uni.switchTab({
						url: '/pages/cart/cart'
					})
					return false
				}

				this.checkoutDisplay = this.checkoutInfo.error || this.checkoutInfo.errors ? false : true
				
				// 【关键修复】如果 checkoutInfo 更新且没有错误，且 order info loading 还在显示，则关闭 loading
				// 这是为了确保即使 checkoutPromise.then() 没有执行，loading 也能被关闭
				if (this.checkoutDisplay && !this.checkoutInfo.error && !this.checkoutInfo.errors && !this.checkoutLoadingClosed && this.orderInfoLoadingActive) {
					this.checkoutLoadingClosed = true;
					this.orderInfoLoadingActive = false;
					// 使用 nextTick 确保在下一个事件循环中关闭，避免与其他逻辑冲突
					this.$nextTick(() => {
						uni.hideLoading();
					});
				}

				// 【修复】智能处理 userBalanceModified 和 userCreditModified 标记
				// 如果有保存的支付状态，先恢复用户修改标记，避免被自动逻辑覆盖
				if (this.savedPaymentState) {
					this.userBalanceModified = this.savedPaymentState.userBalanceModified || false;
					this.userCreditModified = this.savedPaymentState.userCreditModified || false;
				} else {
					// 【关键修复】检查商品列表是否变化，如果变化则重置标记
					// 这样可以确保在商品变化时，如果价格满足条件，可以自动开启
					const currentRecList = this.checkoutInfo && this.checkoutInfo.total && Array.isArray(this.checkoutInfo.total.rec_list) 
						? this.checkoutInfo.total.rec_list.join(',') : '';
					const lastRecList = this.lastRecList && Array.isArray(this.lastRecList) 
						? this.lastRecList.join(',') : '';
					
					// 如果商品列表变化，重置用户修改标记，允许重新自动应用
					if (currentRecList !== lastRecList && currentRecList && lastRecList) {
						this.userBalanceModified = false;
						this.userCreditModified = false;
					}
					
					this.autoPriorityApplied = false;
				}
			this.prioritySelectingValueCard = false;
				this.balanceToggleDisabled = false;
				this.balanceToggleDisabledReason = '';
				this.creditToggleDisabled = false;
				this.creditToggleDisabledReason = '';
			this.initializingPaymentToggles = true;
				this.initializeShopGoodsCollapsed();
				this.seedPersistedValueCardFromTotal('checkoutInfo watch');
				
				// 【关键修复】保存 order info 的原始 amount（已减折扣，未减优惠券），用于初始化时使用
				if (this.checkoutInfo && this.checkoutInfo.total && this.checkoutInfo.total.amount !== undefined) {
					this.orderInfoOriginalAmount = Number(this.checkoutInfo.total.amount) || 0;
				}

				const valueCardPrerequisiteReady =
					this.checkoutInfo &&
					this.checkoutInfo.total &&
					Array.isArray(this.checkoutInfo.total.rec_list) &&
					this.checkoutInfo.total.rec_list.length > 0;

				if (valueCardPrerequisiteReady) {
					if (!this.checkoutInfoLoadedAt) {
						this.checkoutInfoLoadedAt = Date.now();
					}
					this.valueCardLoad();
				} else {
					this.scheduleValueCardLoadRetry('checkoutInfo watch');
				}

				if (this.checkoutInfo.error) {
					switch (this.checkoutInfo.error) {
						case 'address':
							uni.showModal({
								content: this.$t('lang.goto_add_address'),
								success: (res) => {
									if (res.confirm) {
										uni.navigateTo({
											url: '/pagesB/address/addressEdit'
										})
									} else if (res.cancel) {
										uni.switchTab({
											url: '/pages/cart/cart'
										})
									}
								}
							});
							break
						case 'excess':
							uni.showModal({
								content: this.checkoutInfo.msg,
								showCancel: false,
								confirmText: this.$t('lang.back'),
								success: (res) => {
									if (res.confirm) {
										uni.switchTab({
											url: '/pages/cart/cart'
										})
									}
								}
							})
							break
					}

					return false
				}

				const balanceMethod = (this.payment_method || []).find(item => item.pay_id === 11 || item.pay_name === this.balancePaymentLabel);

				//默认选中支付  is_checked  = 1
				if (this.pay_name == '') {
					if (Array.isArray(this.payment_method) && this.payment_method.length > 0) {
						this.payment_method.forEach(v => {
							if (v.is_checked == 1) {
								this.pay_name = v.pay_name
								this.pay_id = v.pay_id
								this.pay_code = v.pay_code
								this.balance_money = v.use_list && v.use_list.money ? v.use_list.money : 0
								// 【关键修复】如果用户已开启信用付，保持计算的值，不使用后端返回的值
								if (this.use_credit_val !== 1) {
									this.surplus_credit_line = v.use_list && v.use_list.surplus_credit_line ? v.use_list.surplus_credit_line : 0
								}
							}
						})
					}
				} else if (this.pay_id === 11 || this.pay_name == this.balancePaymentLabel) {
					this.balance_money = this.balance_money || (balanceMethod && balanceMethod.use_list && balanceMethod.use_list.money) || 0
					// 【关键修复】如果用户已开启信用付，保持计算的值，不使用后端返回的值
					if (this.use_credit_val !== 1) {
						this.surplus_credit_line = this.surplus_credit_line || (balanceMethod && balanceMethod.use_list && balanceMethod.use_list.surplus_credit_line) || 0
					}
				}

			this.payDisplayName = this.pay_name;
			this.submit_pay_id = this.pay_id;
			this.submit_pay_code = this.pay_code;
			
			// 【关键修复】只有在用户没有明确关闭余额开关时，才根据 pay_id 判断
			// 如果用户明确关闭了余额开关（userBalanceModified = true），保持用户的选择
			// 【新增逻辑】如果储值卡数据尚未就绪（valueCardLoaded 为 false），不在这里自动开启余额，
			// 避免在后续储值卡完全覆盖时出现“余额先开启再关闭”的闪烁，由 ensurePaymentPriority 统一处理
			if (!this.userBalanceModified) {
				if (!this.valueCardLoaded) {
					// 初次进入且储值卡数据未加载完成：保持余额关闭状态
					this.balancePaymentActive = false;
					this.use_surplus_val = 0;
				} else {
					const shouldBeActive = (this.pay_id === 11 || this.pay_name === this.balancePaymentLabel);
					this.balancePaymentActive = shouldBeActive;
					this.use_surplus_val = shouldBeActive ? 1 : 0; // 【修复】与balancePaymentActive严格同步
				}
			}
			// 如果用户明确修改过，保持当前状态（不重新设置）

			// 【修复】确保按钮状态与 payment_info 同步
			if (this.balancePaymentActive && !this.userBalanceModified) {
				// 【关键修复】只有在用户没有明确关闭余额开关时，才自动设置 use_surplus_val
				const activeBalanceOption = balanceMethod || this.getBalancePaymentOption();
				const availableBalance = activeBalanceOption && activeBalanceOption.use_list ? Number(activeBalanceOption.use_list
					.money || 0) : 0;
				const availableCredit = activeBalanceOption && activeBalanceOption.use_list ? Number(activeBalanceOption.use_list
					.surplus_credit_line || 0) : 0;

				this.balance_money = availableBalance;
			// 【关键修复】surplus_credit_line 是已使用的信用付金额，应该由后续计算得出，所以重置为0
				this.surplus_credit_line = 0;
				this.balance_money_available = availableBalance;
				this.surplus_credit_line_available = availableCredit;

				this.balancePaymentActive = true;
			this.use_surplus_val = 1; // 【修复】与balancePaymentActive严格同步
			// 【关键修复】不要在这里强制重置 use_credit_val，让 ensurePaymentPriority 来决定是否应该开启信用付
			// 如果余额已开启且有剩余金额需要信用付，ensurePaymentPriority 会自动开启
			// this.use_credit_val = 0; // 已移除：让 ensurePaymentPriority 来决定
			// 【修复】确保在按钮状态正确时才计算 payment_info
			this.applyBalancePaymentState({
				silent: true
			});
			} else if (this.balancePaymentActive && this.userBalanceModified) {
				// 【修复】如果 balancePaymentActive 为 true 但 userBalanceModified 为 true
				// 需要确保 use_surplus_val 与 balancePaymentActive 同步，并重新计算 payment_info
				if (this.use_surplus_val === 0) {
					this.use_surplus_val = 1;
				}
				// 重新计算 payment_info，确保与按钮状态同步
				this.applyBalancePaymentState({
					silent: true
				});
			} else {
					// 【修复】确保balancePaymentActive为false时，use_surplus_val同步为0
					// 如果balancePaymentActive为true但userBalanceModified为true，保持用户的选择，不修改use_surplus_val
					
					// 【关键修复】即使 balancePaymentActive 为 false，也应该初始化 surplus_credit_line_available
					// 这样可以确保先用后付行能够正确显示（只要后端返回了信用付额度）
					const activeBalanceOption = balanceMethod || this.getBalancePaymentOption();
					if (activeBalanceOption && activeBalanceOption.use_list) {
						const availableCredit = Number(activeBalanceOption.use_list.surplus_credit_line || 0);
						if (availableCredit > 0) {
							this.surplus_credit_line_available = availableCredit;
						}
					}
					
					if (!this.balancePaymentActive) {
					this.use_surplus_val = 0;
						// 【关键修复】如果按钮关闭，重置 payment_info
						// 但是，如果API回调已经更新了remaining_debt（通过检查checkoutInfo.total.amount），不要覆盖
						const latestTotal = this.checkoutInfo && this.checkoutInfo.total ? this.checkoutInfo.total : this.total;
						const apiAmount = latestTotal && latestTotal.amount !== undefined ? Number(latestTotal.amount) : null;
						
						// 如果API已经返回了正确的amount，使用API返回的值更新remaining_debt，而不是重置
						if (apiAmount !== null && apiAmount > 0) {
							if (this.payment_info) {
								this.$set(this.payment_info, 'remaining_debt', this.moneyPrecision(apiAmount));
							}
						} else {
							// 如果API还没有返回，使用正确的原始金额（goods_price + shippingFee - couponsMoney）
							const goodsPrice = latestTotal && latestTotal.goods_price ? Number(latestTotal.goods_price) : 0;
							const shippingFee = this.shippingFee ? Number(this.shippingFee) : 0;
							const couponsMoney = Number(this.couponsObject && this.couponsObject.couponsMoney ? this.couponsObject.couponsMoney : 0);
							const resetAmountSource = this.moneyPrecision(goodsPrice + shippingFee - couponsMoney);
							this.resetPaymentStatus(resetAmountSource);
						}
					}
					this.use_credit_val = 0;
					this.payDisplayName = this.pay_name;
					this.submit_pay_id = this.pay_id;
					this.submit_pay_code = this.pay_code;
					const currentOption = this.collectCurrentPaymentOption();
					if (currentOption) {
						this.rememberLastNonBalancePayment(currentOption);
					}
					if (!this.balancePaymentActive) {
					this.princeType = false;
					}
				}

				// 【修复】Android 上的异步时序问题
				// 使用 Promise 确保状态同步，避免时序问题
				this.$nextTick(() => {
					// 确保在下一个事件循环中执行，但使用 Promise 确保状态已同步
					Promise.resolve().then(() => {
						// 再次检查状态是否同步
						if (this.balancePaymentActive && this.use_surplus_val === 0) {
							this.use_surplus_val = 1;
						}
						if (!this.balancePaymentActive && this.use_surplus_val !== 0) {
							this.use_surplus_val = 0;
						}
					this.ensurePaymentPriority();
					});
				});

				//是否是门店商品
				if (this.storeCart) {
					this.store_type = ''
					this.store_mobile = this.storeCart.store_mobile
					this.take_time = this.storeCart.take_time
				}

				//跨境身份证信息
				if (this.checkoutInfo.consignee) {
					this.checkout_real_id = this.checkoutInfo.consignee.id_num
					this.checkout_real_name = this.checkoutInfo.consignee.rel_name
				}

				//发票内容
				if (this.checkoutInfo.can_invoice == 1) {
					this.invoice.invoiceConent = this.invoiceValue[0]
				}

				// 领券购买
				if (this.uc_id > 0) {
					this.submitCoupons(this.uc_id)
				}

				//立即付款可以点击
				this.disabled = false
				this.loading = false
			},
			payment_method() {
				if (this.payment_method == '' && !this.checkoutInfo.error) {
					uni.showToast({
						title: this.$t('lang.payment_method_not_installed'),
						icon: 'none'
					})
					return false
				}
			},
			processedGoodsList: {
				handler(newList) {
					this.initializeShopGoodsCollapsed(newList);
				},
				immediate: true
			},
			shipping() {
				this.shipping_id = [];
				this.shipping_code = [];
				this.shipping_name = [];
				this.format_shipping_fee = [];
				this.shipping_fee = [];
				this.shipping_type = [];
				this.rate_price = [];

				//获取默认配送放id,code,type
				this.shipping.forEach((v) => {
					if (v == undefined && this.store_id == 0) {
						this.shipping_name.push('')
						uni.showToast({
							title: this.$t('lang.noshipping_list_propmt'),
							icon: 'none'
						})
						return false
					}

					this.shipping_id.push(v.shipping_id)
					this.shipping_code.push(v.shipping_code)
					this.shipping_name.push(v.shipping_name)
					this.format_shipping_fee.push(v.format_shipping_fee)
					this.shipping_fee.push(v.shipping_fee)
					this.shipping_type.push(0)
					this.rate_price.push(v.rate_price)
				})
			},
			address_id() {
				//跨境身份证信息
				if (this.checkoutInfo.consignee) {
					this.checkout_real_id = this.checkoutInfo.consignee.id_num
					this.checkout_real_name = this.checkoutInfo.consignee.rel_name
				}
			},
			shopCouponList() {
				// 【关键修复】当 shopCouponList 变化时，重新初始化 couponsId 数组
				// 先清空旧的 couponsId，然后根据新的 shopCouponList 长度重新创建
				// 这样可以确保 couponsId 数组与当前的店铺数量一致，避免使用旧的优惠券ID
				this.couponsObject.couponsId = [];
